content:
* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

html {
  scroll-behavior: smooth;
}

body {
  font-family: "Inter", sans-serif;
  background-color: #0f0f23;
  color: #ffffff;
  line-height: 1.7;
  overflow-x: hidden;
}

h1, h2, h3, h4, h5, h6 {
  font-family: "Space Grotesk", sans-serif;
  font-weight: 700;
  line-height: 1.3;
  margin-bottom: 1rem;
}

h1 {
  font-size: 3.5rem;
}

h2 {
  font-size: 2.5rem;
}

h3 {
  font-size: 1.75rem;
}

h4 {
  font-size: 1.25rem;
}

p {
  color: #a1a1aa;
  margin-bottom: 1rem;
}

a {
  color: #8b5cf6;
  text-decoration: none;
  transition: all 0.3s ease;
}
a:hover {
  color: #a78bfa;
}

img {
  max-width: 100%;
  height: auto;
}

.container {
  max-width: 1200px;
  margin: 0 auto;
  padding: 0 15px;
}

.preloader {
  position: fixed;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  background: #070714;
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 99999;
}
.preloader .loader {
  width: 60px;
  height: 60px;
  border: 3px solid rgba(139, 92, 246, 0.2);
  border-top-color: #8b5cf6;
  border-radius: 50%;
  animation: spin 1s linear infinite;
}
.preloader .loader::after {
  content: "";
  position: absolute;
  width: 40px;
  height: 40px;
  border: 3px solid rgba(236, 72, 153, 0.2);
  border-bottom-color: #ec4899;
  border-radius: 50%;
  animation: spin 0.8s linear infinite reverse;
}

@keyframes spin {
  to {
    transform: rotate(360deg);
  }
}
.top-bar {
  background: #070714;
  padding: 10px 0;
  border-bottom: 1px solid rgba(139, 92, 246, 0.1);
  font-size: 0.875rem;
}
.top-bar .contact-info {
  display: flex;
  gap: 25px;
}
.top-bar .contact-info span {
  color: #a1a1aa;
}
.top-bar .contact-info span i {
  color: #8b5cf6;
  margin-right: 8px;
}
.top-bar .top-links {
  display: flex;
  align-items: center;
  gap: 20px;
}
.top-bar .top-links a {
  color: #a1a1aa;
  font-size: 0.875rem;
}
.top-bar .top-links a:hover {
  color: #8b5cf6;
}
.top-bar .top-links .social-links {
  display: flex;
  gap: 12px;
  margin-left: 15px;
}
.top-bar .top-links .social-links a {
  width: 32px;
  height: 32px;
  display: flex;
  align-items: center;
  justify-content: center;
  background: rgba(139, 92, 246, 0.1);
  border-radius: 50%;
}
.top-bar .top-links .social-links a:hover {
  background: #8b5cf6;
  color: #ffffff;
}

.navbar-main {
  background: transparent;
  padding: 15px 0;
  transition: all 0.3s ease;
}
.navbar-main.scrolled {
  background: rgba(7, 7, 20, 0.95);
  backdrop-filter: blur(10px);
  box-shadow: 0 5px 30px rgba(0, 0, 0, 0.3);
  padding: 10px 0;
}
.navbar-main .navbar-brand {
  font-family: "Space Grotesk", sans-serif;
  font-size: 1.75rem;
  font-weight: 700;
  color: #ffffff;
}
.navbar-main .navbar-brand .brand-icon {
  width: 45px;
  height: 45px;
  background: linear-gradient(135deg, #8b5cf6 0%, #ec4899 100%);
  border-radius: 12px;
  display: flex;
  align-items: center;
  justify-content: center;
  margin-right: 10px;
}
.navbar-main .navbar-brand .brand-icon i {
  font-size: 1.5rem;
  color: #ffffff;
}
.navbar-main .navbar-brand span {
  background: linear-gradient(135deg, #8b5cf6 0%, #ec4899 100%);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}
.navbar-main .nav-link {
  color: #ffffff;
  font-weight: 500;
  padding: 10px 18px;
  margin: 0 3px;
  border-radius: 12px;
  transition: all 0.3s ease;
}
.navbar-main .nav-link:hover, .navbar-main .nav-link.active {
  color: #8b5cf6;
  background: rgba(139, 92, 246, 0.1);
}
.navbar-main .dropdown-menu {
  background: #1a1a2e;
  border: 1px solid rgba(139, 92, 246, 0.2);
  border-radius: 12px;
  padding: 10px;
}
.navbar-main .dropdown-menu .dropdown-item {
  color: #a1a1aa;
  padding: 10px 15px;
  border-radius: 8px;
}
.navbar-main .dropdown-menu .dropdown-item:hover {
  background: rgba(139, 92, 246, 0.1);
  color: #8b5cf6;
}
.navbar-main .btn-quote {
  background: linear-gradient(135deg, #8b5cf6 0%, #ec4899 100%);
  color: #ffffff;
  padding: 12px 28px;
  border-radius: 50px;
  font-weight: 600;
  border: none;
}
.navbar-main .btn-quote:hover {
  transform: translateY(-2px);
  box-shadow: 0 0 20px rgba(139, 92, 246, 0.3), 0 0 40px rgba(139, 92, 246, 0.1);
}
.navbar-main .phone-info {
  text-align: right;
  margin-right: 20px;
}
.navbar-main .phone-info small {
  color: #a1a1aa;
  font-size: 0.75rem;
}
.navbar-main .phone-info strong {
  display: block;
  color: #ffffff;
  font-size: 1.1rem;
}
.navbar-main .phone-info strong i {
  color: #8b5cf6;
  margin-right: 5px;
}

.hero-section {
  min-height: 100vh;
  background: #0f0f23;
  position: relative;
  overflow: hidden;
  padding: 150px 0 100px;
}
.hero-section::before {
  content: "";
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  background: linear-gradient(135deg, rgba(139, 92, 246, 0.1) 0%, rgba(236, 72, 153, 0.1) 100%);
  pointer-events: none;
}
.hero-section .hero-particles {
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  overflow: hidden;
}
.hero-section .hero-particles .particle {
  position: absolute;
  width: 4px;
  height: 4px;
  background: #8b5cf6;
  border-radius: 50%;
  animation: float 15s infinite;
  opacity: 0.5;
}
.hero-section .hero-content {
  position: relative;
  z-index: 2;
}
.hero-section .hero-content .subtitle {
  color: #8b5cf6;
  font-size: 1rem;
  font-weight: 600;
  letter-spacing: 3px;
  text-transform: uppercase;
  margin-bottom: 20px;
}
.hero-section .hero-content .subtitle i {
  margin-right: 10px;
}
.hero-section .hero-content h1 {
  font-size: 3.5rem;
  margin-bottom: 25px;
}
.hero-section .hero-content h1 .highlight {
  background: linear-gradient(135deg, #8b5cf6 0%, #ec4899 100%);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}
.hero-section .hero-content p {
  font-size: 1.2rem;
  max-width: 550px;
  margin-bottom: 35px;
}
.hero-section .hero-content .hero-buttons {
  display: flex;
  gap: 15px;
  flex-wrap: wrap;
}
.hero-section .hero-image {
  position: relative;
}
.hero-section .hero-image img {
  border-radius: 20px;
  box-shadow: 0 0 20px rgba(139, 92, 246, 0.3), 0 0 40px rgba(139, 92, 246, 0.1);
}
.hero-section .hero-image .floating-card {
  position: absolute;
  background: #1a1a2e;
  padding: 20px;
  border-radius: 12px;
  border: 1px solid rgba(139, 92, 246, 0.2);
}
.hero-section .hero-image .floating-card.card-1 {
  top: 20%;
  left: -50px;
  animation: float 3s ease-in-out infinite;
}
.hero-section .hero-image .floating-card.card-2 {
  bottom: 20%;
  right: -30px;
  animation: float 3s ease-in-out infinite 0.5s;
}
.hero-section .hero-image .floating-card i {
  font-size: 2rem;
  color: #8b5cf6;
  margin-bottom: 10px;
}
.hero-section .hero-image .floating-card h4 {
  font-size: 1rem;
  margin-bottom: 5px;
}
.hero-section .hero-image .floating-card p {
  font-size: 0.875rem;
  margin: 0;
}

@keyframes float {
  0%, 100% {
    transform: translateY(0);
  }
  50% {
    transform: translateY(-20px);
  }
}
.btn-primary-custom {
  background: linear-gradient(135deg, #8b5cf6 0%, #ec4899 100%);
  color: #ffffff;
  padding: 14px 32px;
  border-radius: 50px;
  font-weight: 600;
  border: none;
  display: inline-flex;
  align-items: center;
  gap: 10px;
  transition: all 0.3s ease;
}
.btn-primary-custom:hover {
  transform: translateY(-3px);
  box-shadow: 0 0 20px rgba(139, 92, 246, 0.3), 0 0 40px rgba(139, 92, 246, 0.1);
  color: #ffffff;
}

.btn-outline-custom {
  background: transparent;
  color: #ffffff;
  padding: 14px 32px;
  border-radius: 50px;
  font-weight: 600;
  border: 2px solid rgba(139, 92, 246, 0.5);
  display: inline-flex;
  align-items: center;
  gap: 10px;
  transition: all 0.3s ease;
}
.btn-outline-custom:hover {
  background: rgba(139, 92, 246, 0.1);
  border-color: #8b5cf6;
  color: #8b5cf6;
}

.section-padding {
  padding: 100px 0;
}

.section-header {
  text-align: center;
  margin-bottom: 60px;
}
.section-header .section-subtitle {
  color: #8b5cf6;
  font-size: 0.875rem;
  font-weight: 600;
  letter-spacing: 3px;
  text-transform: uppercase;
  margin-bottom: 15px;
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 10px;
}
.section-header .section-subtitle::before, .section-header .section-subtitle::after {
  content: "";
  width: 30px;
  height: 2px;
  background: linear-gradient(135deg, #8b5cf6 0%, #ec4899 100%);
}
.section-header h2 {
  font-size: 2.5rem;
  margin-bottom: 20px;
}
.section-header h2 .highlight {
  background: linear-gradient(135deg, #8b5cf6 0%, #ec4899 100%);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}
.section-header p {
  max-width: 600px;
  margin: 0 auto;
}

.services-section {
  background: #070714;
}
.services-section .service-card {
  background: #1a1a2e;
  border-radius: 20px;
  padding: 40px 30px;
  text-align: center;
  border: 1px solid rgba(139, 92, 246, 0.1);
  transition: all 0.3s ease;
  height: 100%;
}
.services-section .service-card:hover {
  transform: translateY(-10px);
  border-color: #8b5cf6;
  box-shadow: 0 0 20px rgba(139, 92, 246, 0.3), 0 0 40px rgba(139, 92, 246, 0.1);
}
.services-section .service-card:hover .service-icon {
  background: linear-gradient(135deg, #8b5cf6 0%, #ec4899 100%);
}
.services-section .service-card:hover .service-icon i {
  color: #ffffff;
}
.services-section .service-card .service-icon {
  width: 90px;
  height: 90px;
  background: rgba(139, 92, 246, 0.1);
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  margin: 0 auto 25px;
  transition: all 0.3s ease;
}
.services-section .service-card .service-icon i {
  font-size: 2.5rem;
  color: #8b5cf6;
  transition: all 0.3s ease;
}
.services-section .service-card h4 {
  margin-bottom: 15px;
}
.services-section .service-card p {
  font-size: 0.95rem;
  margin-bottom: 20px;
}
.services-section .service-card .service-link {
  color: #8b5cf6;
  font-weight: 600;
}
.services-section .service-card .service-link i {
  margin-left: 5px;
  transition: all 0.3s ease;
}
.services-section .service-card .service-link:hover i {
  transform: translateX(5px);
}

.about-section .about-image {
  position: relative;
}
.about-section .about-image img {
  border-radius: 20px;
}
.about-section .about-image .experience-badge {
  position: absolute;
  bottom: 30px;
  left: -30px;
  background: linear-gradient(135deg, #8b5cf6 0%, #ec4899 100%);
  padding: 25px;
  border-radius: 12px;
  text-align: center;
}
.about-section .about-image .experience-badge .number {
  font-size: 3rem;
  font-weight: 700;
  line-height: 1;
}
.about-section .about-image .experience-badge span {
  font-size: 0.875rem;
}
.about-section .about-content {
  padding-left: 40px;
}
.about-section .about-content .section-subtitle {
  justify-content: flex-start;
}
.about-section .about-content .section-subtitle::before {
  display: none;
}
.about-section .about-content h2 {
  text-align: left;
}
.about-section .about-content .feature-list {
  margin: 30px 0;
}
.about-section .about-content .feature-list .feature-item {
  display: flex;
  align-items: flex-start;
  gap: 15px;
  margin-bottom: 20px;
}
.about-section .about-content .feature-list .feature-item .feature-icon {
  width: 50px;
  height: 50px;
  background: rgba(139, 92, 246, 0.1);
  border-radius: 12px;
  display: flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
}
.about-section .about-content .feature-list .feature-item .feature-icon i {
  color: #8b5cf6;
  font-size: 1.25rem;
}
.about-section .about-content .feature-list .feature-item h5 {
  margin-bottom: 5px;
  font-size: 1.1rem;
}
.about-section .about-content .feature-list .feature-item p {
  margin: 0;
  font-size: 0.9rem;
}

.stats-section {
  background: linear-gradient(135deg, #8b5cf6 0%, #ec4899 100%);
  padding: 60px 0;
}
.stats-section .stat-item {
  text-align: center;
}
.stats-section .stat-item .stat-icon {
  width: 70px;
  height: 70px;
  background: rgba(255, 255, 255, 0.2);
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  margin: 0 auto 15px;
}
.stats-section .stat-item .stat-icon i {
  font-size: 1.75rem;
  color: #ffffff;
}
.stats-section .stat-item .stat-number {
  font-size: 3rem;
  font-weight: 700;
  color: #ffffff;
  line-height: 1;
  margin-bottom: 5px;
}
.stats-section .stat-item p {
  color: rgba(255, 255, 255, 0.8);
  margin: 0;
  font-weight: 500;
}

.portfolio-section {
  background: #070714;
}
.portfolio-section .filter-buttons {
  display: flex;
  justify-content: center;
  gap: 10px;
  margin-bottom: 40px;
  flex-wrap: wrap;
}
.portfolio-section .filter-buttons .filter-btn {
  background: transparent;
  color: #a1a1aa;
  padding: 10px 25px;
  border: 1px solid rgba(139, 92, 246, 0.3);
  border-radius: 50px;
  font-weight: 500;
  cursor: pointer;
  transition: all 0.3s ease;
}
.portfolio-section .filter-buttons .filter-btn:hover, .portfolio-section .filter-buttons .filter-btn.active {
  background: linear-gradient(135deg, #8b5cf6 0%, #ec4899 100%);
  color: #ffffff;
  border-color: transparent;
}
.portfolio-section .portfolio-item {
  margin-bottom: 30px;
}
.portfolio-section .portfolio-item .portfolio-card {
  position: relative;
  border-radius: 12px;
  overflow: hidden;
}
.portfolio-section .portfolio-item .portfolio-card img {
  width: 100%;
  height: 280px;
  object-fit: cover;
  transition: all 0.3s ease;
}
.portfolio-section .portfolio-item .portfolio-card .portfolio-overlay {
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  background: linear-gradient(to top, rgba(7, 7, 20, 0.95) 0%, transparent 100%);
  display: flex;
  align-items: center;
  justify-content: center;
  flex-direction: column;
  opacity: 0;
  transition: all 0.3s ease;
  padding: 20px;
}
.portfolio-section .portfolio-item .portfolio-card .portfolio-overlay .category {
  color: #8b5cf6;
  font-size: 0.875rem;
  font-weight: 600;
  margin-bottom: 10px;
}
.portfolio-section .portfolio-item .portfolio-card .portfolio-overlay h4 {
  color: #ffffff;
  margin-bottom: 15px;
}
.portfolio-section .portfolio-item .portfolio-card .portfolio-overlay .btn-view {
  width: 50px;
  height: 50px;
  background: linear-gradient(135deg, #8b5cf6 0%, #ec4899 100%);
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  color: #ffffff;
}
.portfolio-section .portfolio-item .portfolio-card .portfolio-overlay .btn-view:hover {
  transform: scale(1.1);
}
.portfolio-section .portfolio-item .portfolio-card:hover img {
  transform: scale(1.1);
}
.portfolio-section .portfolio-item .portfolio-card:hover .portfolio-overlay {
  opacity: 1;
}

.pricing-section .pricing-toggle {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 15px;
  margin-bottom: 50px;
}
.pricing-section .pricing-toggle span {
  font-weight: 500;
}
.pricing-section .pricing-toggle span.active {
  color: #8b5cf6;
}
.pricing-section .pricing-toggle .toggle-switch {
  width: 60px;
  height: 30px;
  background: rgba(139, 92, 246, 0.2);
  border-radius: 50px;
  position: relative;
  cursor: pointer;
}
.pricing-section .pricing-toggle .toggle-switch .toggle-slider {
  width: 24px;
  height: 24px;
  background: linear-gradient(135deg, #8b5cf6 0%, #ec4899 100%);
  border-radius: 50%;
  position: absolute;
  top: 3px;
  left: 3px;
  transition: all 0.3s ease;
}
.pricing-section .pricing-toggle .toggle-switch.active .toggle-slider {
  left: 33px;
}
.pricing-section .pricing-toggle .discount-badge {
  background: rgba(16, 185, 129, 0.2);
  color: #10b981;
  padding: 5px 12px;
  border-radius: 50px;
  font-size: 0.75rem;
  font-weight: 600;
}
.pricing-section .pricing-card {
  background: #1a1a2e;
  border-radius: 20px;
  padding: 40px 30px;
  text-align: center;
  border: 1px solid rgba(139, 92, 246, 0.1);
  transition: all 0.3s ease;
  height: 100%;
}
.pricing-section .pricing-card.featured {
  border-color: #8b5cf6;
  transform: scale(1.05);
  box-shadow: 0 0 20px rgba(139, 92, 246, 0.3), 0 0 40px rgba(139, 92, 246, 0.1);
}
.pricing-section .pricing-card.featured .popular-badge {
  position: absolute;
  top: -12px;
  left: 50%;
  transform: translateX(-50%);
  background: linear-gradient(135deg, #8b5cf6 0%, #ec4899 100%);
  padding: 5px 20px;
  border-radius: 50px;
  font-size: 0.75rem;
  font-weight: 600;
}
.pricing-section .pricing-card:hover {
  transform: translateY(-10px);
  border-color: #8b5cf6;
}
.pricing-section .pricing-card .plan-name {
  font-size: 1.25rem;
  margin-bottom: 20px;
}
.pricing-section .pricing-card .plan-price {
  margin-bottom: 30px;
}
.pricing-section .pricing-card .plan-price .currency {
  font-size: 1.5rem;
  vertical-align: top;
}
.pricing-section .pricing-card .plan-price .amount {
  font-size: 4rem;
  font-weight: 700;
  background: linear-gradient(135deg, #8b5cf6 0%, #ec4899 100%);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}
.pricing-section .pricing-card .plan-price .period {
  color: #a1a1aa;
}
.pricing-section .pricing-card .plan-features {
  list-style: none;
  padding: 0;
  margin-bottom: 30px;
}
.pricing-section .pricing-card .plan-features li {
  padding: 12px 0;
  border-bottom: 1px solid rgba(139, 92, 246, 0.1);
  color: #a1a1aa;
}
.pricing-section .pricing-card .plan-features li i {
  margin-right: 10px;
}
.pricing-section .pricing-card .plan-features li i.fa-check {
  color: #10b981;
}
.pricing-section .pricing-card .plan-features li i.fa-times {
  color: #ef4444;
}
.pricing-section .pricing-card .plan-features li:last-child {
  border-bottom: none;
}

.testimonials-section {
  background: #070714;
}
.testimonials-section .testimonial-card {
  background: #1a1a2e;
  border-radius: 20px;
  padding: 40px;
  border: 1px solid rgba(139, 92, 246, 0.1);
}
.testimonials-section .testimonial-card .quote-icon {
  font-size: 3rem;
  color: #8b5cf6;
  opacity: 0.3;
  margin-bottom: 20px;
}
.testimonials-section .testimonial-card p {
  font-size: 1.1rem;
  font-style: italic;
  margin-bottom: 25px;
}
.testimonials-section .testimonial-card .client-info {
  display: flex;
  align-items: center;
  gap: 15px;
}
.testimonials-section .testimonial-card .client-info img {
  width: 60px;
  height: 60px;
  border-radius: 50%;
  object-fit: cover;
}
.testimonials-section .testimonial-card .client-info h5 {
  margin-bottom: 5px;
}
.testimonials-section .testimonial-card .client-info span {
  color: #8b5cf6;
  font-size: 0.875rem;
}
.testimonials-section .testimonial-card .rating {
  margin-top: 15px;
}
.testimonials-section .testimonial-card .rating i {
  color: #f59e0b;
}

.cta-section {
