/**
 * AI Clinic - Soluções em Inteligência Artificial
 * Main JavaScript File with jQuery and AJAX
 */

(function($) {
    'use strict';

    // ==========================================
    // PRELOADER
    // ==========================================
    $(window).on('load', function() {
        $('.preloader').fadeOut(500, function() {
            $(this).remove();
        });
    });

    // ==========================================
    // DOCUMENT READY
    // ==========================================
    $(document).ready(function() {

        // ==========================================
        // NAVBAR SCROLL EFFECT
        // ==========================================
        $(window).on('scroll', function() {
            if ($(this).scrollTop() > 100) {
                $('.navbar-main').addClass('scrolled');
            } else {
                $('.navbar-main').removeClass('scrolled');
            }
        });

        // ==========================================
        // SMOOTH SCROLL
        // ==========================================
        $('a[href*="#"]:not([href="#"])').on('click', function() {
            if (location.pathname.replace(/^\//, '') === this.pathname.replace(/^\//, '') && location.hostname === this.hostname) {
                var target = $(this.hash);
                target = target.length ? target : $('[name=' + this.hash.slice(1) + ']');
                if (target.length) {
                    $('html, body').animate({
                        scrollTop: target.offset().top - 80
                    }, 800);
                    return false;
                }
            }
        });

        // ==========================================
        // BACK TO TOP BUTTON
        // ==========================================
        $(window).on('scroll', function() {
            if ($(this).scrollTop() > 300) {
                $('.back-to-top').addClass('show');
            } else {
                $('.back-to-top').removeClass('show');
            }
        });

        $('.back-to-top').on('click', function(e) {
            e.preventDefault();
            $('html, body').animate({scrollTop: 0}, 800);
        });

        // ==========================================
        // COUNTER ANIMATION
        // ==========================================
        var counted = false;
        $(window).on('scroll', function() {
            var statsSection = $('.stats-section');
            if (statsSection.length) {
                var oTop = statsSection.offset().top - window.innerHeight;
                if (!counted && $(window).scrollTop() > oTop) {
                    $('.stat-number').each(function() {
                        var $this = $(this),
                            countTo = $this.attr('data-count');
                        $({ countNum: $this.text() }).animate({
                            countNum: countTo
                        }, {
                            duration: 2000,
                            easing: 'swing',
                            step: function() {
                                $this.text(Math.floor(this.countNum));
                            },
                            complete: function() {
                                $this.text(this.countNum + '+');
                            }
                        });
                    });
                    counted = true;
                }
            }
        });

        // ==========================================
        // PORTFOLIO FILTER
        // ==========================================
        $('.filter-btn').on('click', function() {
            var filterValue = $(this).attr('data-filter');

            $('.filter-btn').removeClass('active');
            $(this).addClass('active');

            if (filterValue === 'all') {
                $('.portfolio-item').fadeIn(300);
            } else {
                $('.portfolio-item').hide();
                $('.portfolio-item[data-category="' + filterValue + '"]').fadeIn(300);
            }
        });

        // ==========================================
        // PARTICLES ANIMATION
        // ==========================================
        function createParticles() {
            var container = $('.hero-particles');
            if (container.length) {
                for (var i = 0; i < 30; i++) {
                    var particle = $('<div class="particle"></div>');
                    particle.css({
                        left: Math.random() * 100 + '%',
                        top: Math.random() * 100 + '%',
                        animationDelay: Math.random() * 5 + 's',
                        animationDuration: (Math.random() * 10 + 10) + 's'
                    });
                    container.append(particle);
                }
            }
        }
        createParticles();

        // ==========================================
        // CONTACT FORM WITH AJAX
        // ==========================================
        $('#contactForm').on('submit', function(e) {
            e.preventDefault();

            var $form = $(this);
            var $btn = $form.find('button[type="submit"]');
            var originalText = $btn.html();

            // Validação básica
            var isValid = true;
            $form.find('[required]').each(function() {
                if (!$(this).val()) {
                    isValid = false;
                    $(this).addClass('is-invalid');
                } else {
                    $(this).removeClass('is-invalid');
                }
            });

            if (!isValid) {
                showAlert('Por favor, preencha todos os campos obrigatórios.', 'danger');
                return;
            }

            $btn.html('<i class="fas fa-spinner fa-spin"></i> Enviando...').prop('disabled', true);

            $.ajax({
                url: 'https://jsonplaceholder.typicode.com/posts',
                method: 'POST',
                data: $form.serialize(),
                success: function(response) {
                    showAlert('Mensagem enviada com sucesso! Nossa equipe de IA entrará em contato.', 'success');
                    $form[0].reset();
                },
                error: function() {
                    showAlert('Mensagem enviada com sucesso! Nossa equipe de IA entrará em contato.', 'success');
                    $form[0].reset();
                },
                complete: function() {
                    $btn.html(originalText).prop('disabled', false);
                }
            });
        });

        // ==========================================
        // NEWSLETTER FORM WITH AJAX
        // ==========================================
        $('#newsletterForm').on('submit', function(e) {
            e.preventDefault();

            var $form = $(this);
            var email = $form.find('input[type="email"]').val();
            var $btn = $form.find('button[type="submit"]');

            if (!email || !validateEmail(email)) {
                showAlert('Por favor, insira um e-mail válido.', 'danger');
                return;
            }

            $btn.html('<i class="fas fa-spinner fa-spin"></i>').prop('disabled', true);

            setTimeout(function() {
                showAlert('Inscrição realizada! Você receberá novidades sobre IA.', 'success');
                $form[0].reset();
                $btn.html('<i class="fas fa-paper-plane"></i>').prop('disabled', false);
            }, 1000);
        });

        // ==========================================
        // CONSULTATION FORM
        // ==========================================
        $('#consultationForm').on('submit', function(e) {
            e.preventDefault();

            var $form = $(this);
            var $btn = $form.find('button[type="submit"]');
            var originalText = $btn.html();

            $btn.html('<i class="fas fa-spinner fa-spin"></i> Agendando...').prop('disabled', true);

            setTimeout(function() {
                showAlert('Consultoria agendada com sucesso! Você receberá um e-mail de confirmação.', 'success');
                $form[0].reset();
                $('#consultationModal').modal('hide');
                $btn.html(originalText).prop('disabled', false);
            }, 1500);
        });

        // ==========================================
        // LOAD MORE PROJECTS
        // ==========================================
        var projectsLoaded = 6;

        $('#loadMoreProjects').on('click', function() {
            var $btn = $(this);
            $btn.html('<i class="fas fa-spinner fa-spin"></i> Carregando...').prop('disabled', true);

            setTimeout(function() {
                var newProjects = `
                    <div class="col-lg-4 col-md-6 portfolio-item" data-category="ml">
                        <div class="portfolio-card">
                            <img src="https://images.unsplash.com/photo-1555949963-ff9fe0c870eb?w=400&h=300&fit=crop" alt="Projeto">
                            <div class="portfolio-overlay">
                                <span class="category">Machine Learning</span>
                                <h4>Sistema de Recomendação</h4>
                                <a href="portfolio.html" class="btn-view"><i class="fas fa-plus"></i></a>
                            </div>
                        </div>
                    </div>
                    <div class="col-lg-4 col-md-6 portfolio-item" data-category="nlp">
                        <div class="portfolio-card">
                            <img src="https://images.unsplash.com/photo-1526374965328-7f61d4dc18c5?w=400&h=300&fit=crop" alt="Projeto">
                            <div class="portfolio-overlay">
                                <span class="category">NLP</span>
                                <h4>Tradução Automática</h4>
                                <a href="portfolio.html" class="btn-view"><i class="fas fa-plus"></i></a>
                            </div>
                        </div>
                    </div>
                    <div class="col-lg-4 col-md-6 portfolio-item" data-category="chatbot">
                        <div class="portfolio-card">
                            <img src="https://images.unsplash.com/photo-1531746790731-6c087fecd65a?w=400&h=300&fit=crop" alt="Projeto">
                            <div class="portfolio-overlay">
                                <span class="category">Chatbot</span>
                                <h4>Assistente de Vendas</h4>
                                <a href="portfolio.html" class="btn-view"><i class="fas fa-plus"></i></a>
                            </div>
                        </div>
                    </div>
                `;

                $('.portfolio-section .row').append(newProjects);
                projectsLoaded += 3;

                if (projectsLoaded >= 12) {
                    $btn.hide();
                } else {
                    $btn.html('Carregar Mais <i class="fas fa-plus"></i>').prop('disabled', false);
                }
            }, 1000);
        });

        // ==========================================
        // FAQ ACCORDION
        // ==========================================
        $('.faq-question').on('click', function() {
            var $item = $(this).closest('.faq-item');
            var $answer = $item.find('.faq-answer');

            if ($item.hasClass('active')) {
                $item.removeClass('active');
                $answer.slideUp(300);
            } else {
                $('.faq-item').removeClass('active');
                $('.faq-answer').slideUp(300);
                $item.addClass('active');
                $answer.slideDown(300);
            }
        });

        // ==========================================
        // PRICING TOGGLE
        // ==========================================
        $('.pricing-toggle .toggle-switch').on('click', function() {
            $(this).toggleClass('active');

            var isAnnual = $(this).hasClass('active');

            if (isAnnual) {
                $('.monthly-label').removeClass('active');
                $('.yearly-label').addClass('active');
            } else {
                $('.monthly-label').addClass('active');
                $('.yearly-label').removeClass('active');
            }

            // Update prices
            $('.pricing-card').each(function() {
                var $amount = $(this).find('.amount');
                var monthlyPrice = parseInt($amount.attr('data-monthly'));

                if (isAnnual) {
                    var annualPrice = Math.round(monthlyPrice * 0.8);
                    $amount.text(annualPrice.toLocaleString('pt-BR'));
                } else {
                    $amount.text(monthlyPrice.toLocaleString('pt-BR'));
                }
            });
        });

        // ==========================================
        // SCROLL REVEAL ANIMATION
        // ==========================================
        function revealOnScroll() {
            var reveals = document.querySelectorAll('.reveal');

            reveals.forEach(function(element) {
                var windowHeight = window.innerHeight;
                var elementTop = element.getBoundingClientRect().top;
                var elementVisible = 150;

                if (elementTop < windowHeight - elementVisible) {
                    element.classList.add('active');
                }
            });
        }

        window.addEventListener('scroll', revealOnScroll);
        revealOnScroll();

        // ==========================================
        // MOBILE MENU
        // ==========================================
        $('.navbar-toggler').on('click', function() {
            $('body').toggleClass('menu-open');
        });

        // ==========================================
        // DROPDOWN HOVER (DESKTOP)
        // ==========================================
        if ($(window).width() > 991) {
            $('.navbar .dropdown').hover(
                function() {
                    $(this).find('.dropdown-menu').stop(true, true).delay(100).fadeIn(200);
                },
                function() {
                    $(this).find('.dropdown-menu').stop(true, true).delay(100).fadeOut(200);
                }
            );
        }

        // ==========================================
        // FORM VALIDATION
        // ==========================================
        $('input, textarea, select').on('blur', function() {
            if ($(this).prop('required') && !$(this).val()) {
                $(this).addClass('is-invalid');
            } else {
                $(this).removeClass('is-invalid');
            }
        });

        // ==========================================
        // NAVBAR ACTIVE LINK
        // ==========================================
        var currentPage = window.location.pathname.split('/').pop();
        $('.nav-link').each(function() {
            var linkHref = $(this).attr('href');
            if (linkHref === currentPage || (currentPage === '' && linkHref === 'index.html')) {
                $(this).addClass('active');
            }
        });

        // ==========================================
        // TOOLTIP INITIALIZATION
        // ==========================================
        var tooltipTriggerList = [].slice.call(document.querySelectorAll('[data-bs-toggle="tooltip"]'));
        tooltipTriggerList.map(function(tooltipTriggerEl) {
            return new bootstrap.Tooltip(tooltipTriggerEl);
        });

        // ==========================================
        // AI DEMO SIMULATION
        // ==========================================
        $('#aiDemoBtn').on('click', function() {
            var $btn = $(this);
            var $result = $('#aiDemoResult');

            $btn.prop('disabled', true).html('<i class="fas fa-spinner fa-spin"></i> Processando...');
            $result.hide();

            // Simulate AI processing
            setTimeout(function() {
                var responses = [
                    'Análise concluída! Detectamos padrões interessantes nos seus dados.',
                    'Modelo treinado com sucesso! Precisão de 94.5%.',
                    'Previsão gerada! Tendência de crescimento de 23% no próximo trimestre.',
                    'Sentimento analisado! 78% positivo, 15% neutro, 7% negativo.'
                ];

                var randomResponse = responses[Math.floor(Math.random() * responses.length)];

                $result.html('<i class="fas fa-check-circle text-success me-2"></i>' + randomResponse).fadeIn();
                $btn.prop('disabled', false).html('<i class="fas fa-play"></i> Testar IA');
            }, 2000);
        });

    }); // End Document Ready

    // ==========================================
    // HELPER FUNCTIONS
    // ==========================================

    function validateEmail(email) {
        var re = /^(([^<>()\[\]\\.,;:\s@"]+(\.[^<>()\[\]\\.,;:\s@"]+)*)|(".+"))@((\[[0-9]{1,3}\.[0-9]{1,3}\.[0-9]{1,3}\.[0-9]{1,3}])|(([a-zA-Z\-0-9]+\.)+[a-zA-Z]{2,}))$/;
        return re.test(String(email).toLowerCase());
    }

    function showAlert(message, type) {
        var bgColor = type === 'success' ? 'linear-gradient(135deg, #8b5cf6, #ec4899)' : 'linear-gradient(135deg, #ef4444, #dc2626)';

        var alertHtml = '<div class="alert-notification" style="' +
            'position: fixed; top: 100px; right: 20px; z-index: 9999; ' +
            'padding: 20px 30px; background: ' + bgColor + '; ' +
            'color: #fff; border-radius: 12px; ' +
            'box-shadow: 0 10px 40px rgba(139, 92, 246, 0.3); ' +
            'transform: translateX(400px); transition: transform 0.4s ease; ' +
            'max-width: 400px; font-weight: 500;">' +
            '<i class="fas fa-' + (type === 'success' ? 'check-circle' : 'exclamation-circle') + ' me-2"></i>' +
            message +
            '</div>';

        $('.alert-notification').remove();
        $('body').append(alertHtml);

        setTimeout(function() {
            $('.alert-notification').css('transform', 'translateX(0)');
        }, 100);

        setTimeout(function() {
            $('.alert-notification').css('transform', 'translateX(400px)');
            setTimeout(function() {
                $('.alert-notification').remove();
            }, 400);
        }, 5000);
    }

})(jQuery);

// ==========================================
// AI Clinic - Clínica de Inteligência Artificial
// Template SCSS - Tema Roxo/Violeta Futurista
// ==========================================

// ==========================================
// VARIABLES
// ==========================================
$primary-color: #8b5cf6;
$primary-dark: #7c3aed;
$primary-light: #a78bfa;
$secondary-color: #ec4899;
$accent-color: #06b6d4;
$success-color: #10b981;
$warning-color: #f59e0b;
$danger-color: #ef4444;

$bg-dark: #0f0f23;
$bg-darker: #070714;
$bg-card: #1a1a2e;
$bg-card-hover: #252542;

$text-light: #ffffff;
$text-muted: #a1a1aa;
$text-gray: #71717a;

$gradient-primary: linear-gradient(135deg, $primary-color 0%, $secondary-color 100%);
$gradient-secondary: linear-gradient(135deg, $accent-color 0%, $primary-color 100%);
$gradient-hero: linear-gradient(135deg, rgba(139, 92, 246, 0.1) 0%, rgba(236, 72, 153, 0.1) 100%);

$font-primary: 'Space Grotesk', sans-serif;
$font-secondary: 'Inter', sans-serif;

$border-radius: 12px;
$border-radius-lg: 20px;
$transition: all 0.3s ease;

// ==========================================
// MIXINS
// ==========================================
@mixin flex-center {
    display: flex;
    align-items: center;
    justify-content: center;
}

@mixin glass-effect {
    background: rgba(26, 26, 46, 0.8);
    backdrop-filter: blur(10px);
    border: 1px solid rgba(139, 92, 246, 0.2);
}

@mixin glow-effect($color) {
    box-shadow: 0 0 20px rgba($color, 0.3), 0 0 40px rgba($color, 0.1);
}

@mixin gradient-text {
    background: $gradient-primary;
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    background-clip: text;
}

// ==========================================
// BASE STYLES
// ==========================================
* {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
}

html {
    scroll-behavior: smooth;
}

body {
    font-family: $font-secondary;
    background-color: $bg-dark;
    color: $text-light;
    line-height: 1.7;
    overflow-x: hidden;
}

h1, h2, h3, h4, h5, h6 {
    font-family: $font-primary;
    font-weight: 700;
    line-height: 1.3;
    margin-bottom: 1rem;
}

h1 { font-size: 3.5rem; }
h2 { font-size: 2.5rem; }
h3 { font-size: 1.75rem; }
h4 { font-size: 1.25rem; }

p {
    color: $text-muted;
    margin-bottom: 1rem;
}

a {
    color: $primary-color;
    text-decoration: none;
    transition: $transition;

    &:hover {
        color: $primary-light;
    }
}

img {
    max-width: 100%;
    height: auto;
}

.container {
    max-width: 1200px;
    margin: 0 auto;
    padding: 0 15px;
}

// ==========================================
// PRELOADER
// ==========================================
.preloader {
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background: $bg-darker;
    @include flex-center;
    z-index: 99999;

    .loader {
        width: 60px;
        height: 60px;
        border: 3px solid rgba($primary-color, 0.2);
        border-top-color: $primary-color;
        border-radius: 50%;
        animation: spin 1s linear infinite;

        &::after {
            content: '';
            position: absolute;
            width: 40px;
            height: 40px;
            border: 3px solid rgba($secondary-color, 0.2);
            border-bottom-color: $secondary-color;
            border-radius: 50%;
            animation: spin 0.8s linear infinite reverse;
        }
    }
}

@keyframes spin {
    to { transform: rotate(360deg); }
}

// ==========================================
// TOP BAR
// ==========================================
.top-bar {
    background: $bg-darker;
    padding: 10px 0;
    border-bottom: 1px solid rgba($primary-color, 0.1);
    font-size: 0.875rem;

    .contact-info {
        display: flex;
        gap: 25px;

        span {
            color: $text-muted;

            i {
                color: $primary-color;
                margin-right: 8px;
            }
        }
    }

    .top-links {
        display: flex;
        align-items: center;
        gap: 20px;

        a {
            color: $text-muted;
            font-size: 0.875rem;

            &:hover {
                color: $primary-color;
            }
        }

        .social-links {
            display: flex;
            gap: 12px;
            margin-left: 15px;

            a {
                width: 32px;
                height: 32px;
                @include flex-center;
                background: rgba($primary-color, 0.1);
                border-radius: 50%;

                &:hover {
                    background: $primary-color;
                    color: $text-light;
                }
            }
        }
    }
}

// ==========================================
// NAVBAR
// ==========================================
.navbar-main {
    background: transparent;
    padding: 15px 0;
    transition: $transition;

    &.scrolled {
        background: rgba($bg-darker, 0.95);
        backdrop-filter: blur(10px);
        box-shadow: 0 5px 30px rgba(0, 0, 0, 0.3);
        padding: 10px 0;
    }

    .navbar-brand {
        font-family: $font-primary;
        font-size: 1.75rem;
        font-weight: 700;
        color: $text-light;

        .brand-icon {
            width: 45px;
            height: 45px;
            background: $gradient-primary;
            border-radius: $border-radius;
            @include flex-center;
            margin-right: 10px;

            i {
                font-size: 1.5rem;
                color: $text-light;
            }
        }

        span {
            @include gradient-text;
        }
    }

    .nav-link {
        color: $text-light;
        font-weight: 500;
        padding: 10px 18px;
        margin: 0 3px;
        border-radius: $border-radius;
        transition: $transition;

        &:hover, &.active {
            color: $primary-color;
            background: rgba($primary-color, 0.1);
        }
    }

    .dropdown-menu {
        background: $bg-card;
        border: 1px solid rgba($primary-color, 0.2);
        border-radius: $border-radius;
        padding: 10px;

        .dropdown-item {
            color: $text-muted;
            padding: 10px 15px;
            border-radius: 8px;

            &:hover {
                background: rgba($primary-color, 0.1);
                color: $primary-color;
            }
        }
    }

    .btn-quote {
        background: $gradient-primary;
        color: $text-light;
        padding: 12px 28px;
        border-radius: 50px;
        font-weight: 600;
        border: none;

        &:hover {
            transform: translateY(-2px);
            @include glow-effect($primary-color);
        }
    }

    .phone-info {
        text-align: right;
        margin-right: 20px;

        small {
            color: $text-muted;
            font-size: 0.75rem;
        }

        strong {
            display: block;
            color: $text-light;
            font-size: 1.1rem;

            i {
                color: $primary-color;
                margin-right: 5px;
            }
        }
    }
}

// ==========================================
// HERO SECTION
// ==========================================
.hero-section {
    min-height: 100vh;
    background: $bg-dark;
    position: relative;
    overflow: hidden;
    padding: 150px 0 100px;

    &::before {
        content: '';
        position: absolute;
        top: 0;
        left: 0;
        width: 100%;
        height: 100%;
        background: $gradient-hero;
        pointer-events: none;
    }

    .hero-particles {
        position: absolute;
        top: 0;
        left: 0;
        width: 100%;
        height: 100%;
        overflow: hidden;

        .particle {
            position: absolute;
            width: 4px;
            height: 4px;
            background: $primary-color;
            border-radius: 50%;
            animation: float 15s infinite;
            opacity: 0.5;
        }
    }

    .hero-content {
        position: relative;
        z-index: 2;

        .subtitle {
            color: $primary-color;
            font-size: 1rem;
            font-weight: 600;
            letter-spacing: 3px;
            text-transform: uppercase;
            margin-bottom: 20px;

            i {
                margin-right: 10px;
            }
        }

        h1 {
            font-size: 3.5rem;
            margin-bottom: 25px;

            .highlight {
                @include gradient-text;
            }
        }

        p {
            font-size: 1.2rem;
            max-width: 550px;
            margin-bottom: 35px;
        }

        .hero-buttons {
            display: flex;
            gap: 15px;
            flex-wrap: wrap;
        }
    }

    .hero-image {
        position: relative;

        img {
            border-radius: $border-radius-lg;
            @include glow-effect($primary-color);
        }

        .floating-card {
            position: absolute;
            background: $bg-card;
            padding: 20px;
            border-radius: $border-radius;
            border: 1px solid rgba($primary-color, 0.2);

            &.card-1 {
                top: 20%;
                left: -50px;
                animation: float 3s ease-in-out infinite;
            }

            &.card-2 {
                bottom: 20%;
                right: -30px;
                animation: float 3s ease-in-out infinite 0.5s;
            }

            i {
                font-size: 2rem;
                color: $primary-color;
                margin-bottom: 10px;
            }

            h4 {
                font-size: 1rem;
                margin-bottom: 5px;
            }

            p {
                font-size: 0.875rem;
                margin: 0;
            }
        }
    }
}

@keyframes float {
    0%, 100% { transform: translateY(0); }
    50% { transform: translateY(-20px); }
}

// ==========================================
// BUTTONS
// ==========================================
.btn-primary-custom {
    background: $gradient-primary;
    color: $text-light;
    padding: 14px 32px;
    border-radius: 50px;
    font-weight: 600;
    border: none;
    display: inline-flex;
    align-items: center;
    gap: 10px;
    transition: $transition;

    &:hover {
        transform: translateY(-3px);
        @include glow-effect($primary-color);
        color: $text-light;
    }
}

.btn-outline-custom {
    background: transparent;
    color: $text-light;
    padding: 14px 32px;
    border-radius: 50px;
    font-weight: 600;
    border: 2px solid rgba($primary-color, 0.5);
    display: inline-flex;
    align-items: center;
    gap: 10px;
    transition: $transition;

    &:hover {
        background: rgba($primary-color, 0.1);
        border-color: $primary-color;
        color: $primary-color;
    }
}

// ==========================================
// SECTION STYLES
// ==========================================
.section-padding {
    padding: 100px 0;
}

.section-header {
    text-align: center;
    margin-bottom: 60px;

    .section-subtitle {
        color: $primary-color;
        font-size: 0.875rem;
        font-weight: 600;
        letter-spacing: 3px;
        text-transform: uppercase;
        margin-bottom: 15px;
        display: flex;
        align-items: center;
        justify-content: center;
        gap: 10px;

        &::before, &::after {
            content: '';
            width: 30px;
            height: 2px;
            background: $gradient-primary;
        }
    }

    h2 {
        font-size: 2.5rem;
        margin-bottom: 20px;

        .highlight {
            @include gradient-text;
        }
    }

    p {
        max-width: 600px;
        margin: 0 auto;
    }
}

// ==========================================
// SERVICES SECTION
// ==========================================
.services-section {
    background: $bg-darker;

    .service-card {
        background: $bg-card;
        border-radius: $border-radius-lg;
        padding: 40px 30px;
        text-align: center;
        border: 1px solid rgba($primary-color, 0.1);
        transition: $transition;
        height: 100%;

        &:hover {
            transform: translateY(-10px);
            border-color: $primary-color;
            @include glow-effect($primary-color);

            .service-icon {
                background: $gradient-primary;

                i {
                    color: $text-light;
                }
            }
        }

        .service-icon {
            width: 90px;
            height: 90px;
            background: rgba($primary-color, 0.1);
            border-radius: 50%;
            @include flex-center;
            margin: 0 auto 25px;
            transition: $transition;

            i {
                font-size: 2.5rem;
                color: $primary-color;
                transition: $transition;
            }
        }

        h4 {
            margin-bottom: 15px;
        }

        p {
            font-size: 0.95rem;
            margin-bottom: 20px;
        }

        .service-link {
            color: $primary-color;
            font-weight: 600;

            i {
                margin-left: 5px;
                transition: $transition;
            }

            &:hover i {
                transform: translateX(5px);
            }
        }
    }
}

// ==========================================
// ABOUT SECTION
// ==========================================
.about-section {
    .about-image {
        position: relative;

        img {
            border-radius: $border-radius-lg;
        }

        .experience-badge {
            position: absolute;
            bottom: 30px;
            left: -30px;
            background: $gradient-primary;
            padding: 25px;
            border-radius: $border-radius;
            text-align: center;

            .number {
                font-size: 3rem;
                font-weight: 700;
                line-height: 1;
            }

            span {
                font-size: 0.875rem;
            }
        }
    }

    .about-content {
        padding-left: 40px;

        .section-subtitle {
            justify-content: flex-start;

            &::before {
                display: none;
            }
        }

        h2 {
            text-align: left;
        }

        .feature-list {
            margin: 30px 0;

            .feature-item {
                display: flex;
                align-items: flex-start;
                gap: 15px;
                margin-bottom: 20px;

                .feature-icon {
                    width: 50px;
                    height: 50px;
                    background: rgba($primary-color, 0.1);
                    border-radius: $border-radius;
                    @include flex-center;
                    flex-shrink: 0;

                    i {
                        color: $primary-color;
                        font-size: 1.25rem;
                    }
                }

                h5 {
                    margin-bottom: 5px;
                    font-size: 1.1rem;
                }

                p {
                    margin: 0;
                    font-size: 0.9rem;
                }
            }
        }
    }
}

// ==========================================
// STATS SECTION
// ==========================================
.stats-section {
    background: $gradient-primary;
    padding: 60px 0;

    .stat-item {
        text-align: center;

        .stat-icon {
            width: 70px;
            height: 70px;
            background: rgba($text-light, 0.2);
            border-radius: 50%;
            @include flex-center;
            margin: 0 auto 15px;

            i {
                font-size: 1.75rem;
                color: $text-light;
            }
        }

        .stat-number {
            font-size: 3rem;
            font-weight: 700;
            color: $text-light;
            line-height: 1;
            margin-bottom: 5px;
        }

        p {
            color: rgba($text-light, 0.8);
            margin: 0;
            font-weight: 500;
        }
    }
}

// ==========================================
// PORTFOLIO SECTION
// ==========================================
.portfolio-section {
    background: $bg-darker;

    .filter-buttons {
        display: flex;
        justify-content: center;
        gap: 10px;
        margin-bottom: 40px;
        flex-wrap: wrap;

        .filter-btn {
            background: transparent;
            color: $text-muted;
            padding: 10px 25px;
            border: 1px solid rgba($primary-color, 0.3);
            border-radius: 50px;
            font-weight: 500;
            cursor: pointer;
            transition: $transition;

            &:hover, &.active {
                background: $gradient-primary;
                color: $text-light;
                border-color: transparent;
            }
        }
    }

    .portfolio-item {
        margin-bottom: 30px;

        .portfolio-card {
            position: relative;
            border-radius: $border-radius;
            overflow: hidden;

            img {
                width: 100%;
                height: 280px;
                object-fit: cover;
                transition: $transition;
            }

            .portfolio-overlay {
                position: absolute;
                top: 0;
                left: 0;
                width: 100%;
                height: 100%;
                background: linear-gradient(to top, rgba($bg-darker, 0.95) 0%, transparent 100%);
                @include flex-center;
                flex-direction: column;
                opacity: 0;
                transition: $transition;
                padding: 20px;

                .category {
                    color: $primary-color;
                    font-size: 0.875rem;
                    font-weight: 600;
                    margin-bottom: 10px;
                }

                h4 {
                    color: $text-light;
                    margin-bottom: 15px;
                }

                .btn-view {
                    width: 50px;
                    height: 50px;
                    background: $gradient-primary;
                    border-radius: 50%;
                    @include flex-center;
                    color: $text-light;

                    &:hover {
                        transform: scale(1.1);
                    }
                }
            }

            &:hover {
                img {
                    transform: scale(1.1);
                }

                .portfolio-overlay {
                    opacity: 1;
                }
            }
        }
    }
}

// ==========================================
// PRICING SECTION
// ==========================================
.pricing-section {
    .pricing-toggle {
        display: flex;
        align-items: center;
        justify-content: center;
        gap: 15px;
        margin-bottom: 50px;

        span {
            font-weight: 500;

            &.active {
                color: $primary-color;
            }
        }

        .toggle-switch {
            width: 60px;
            height: 30px;
            background: rgba($primary-color, 0.2);
            border-radius: 50px;
            position: relative;
            cursor: pointer;

            .toggle-slider {
                width: 24px;
                height: 24px;
                background: $gradient-primary;
                border-radius: 50%;
                position: absolute;
                top: 3px;
                left: 3px;
                transition: $transition;
            }

            &.active .toggle-slider {
                left: 33px;
            }
        }

        .discount-badge {
            background: rgba($success-color, 0.2);
            color: $success-color;
            padding: 5px 12px;
            border-radius: 50px;
            font-size: 0.75rem;
            font-weight: 600;
        }
    }

    .pricing-card {
        background: $bg-card;
        border-radius: $border-radius-lg;
        padding: 40px 30px;
        text-align: center;
        border: 1px solid rgba($primary-color, 0.1);
        transition: $transition;
        height: 100%;

        &.featured {
            border-color: $primary-color;
            transform: scale(1.05);
            @include glow-effect($primary-color);

            .popular-badge {
                position: absolute;
                top: -12px;
                left: 50%;
                transform: translateX(-50%);
                background: $gradient-primary;
                padding: 5px 20px;
                border-radius: 50px;
                font-size: 0.75rem;
                font-weight: 600;
            }
        }

        &:hover {
            transform: translateY(-10px);
            border-color: $primary-color;
        }

        .plan-name {
            font-size: 1.25rem;
            margin-bottom: 20px;
        }

        .plan-price {
            margin-bottom: 30px;

            .currency {
                font-size: 1.5rem;
                vertical-align: top;
            }

            .amount {
                font-size: 4rem;
                font-weight: 700;
                @include gradient-text;
            }

            .period {
