                height: 45px;
                background: $gradient-primary;
                border-radius: $border-radius;
                @include flex-center;
                margin-right: 10px;

                i {
                    font-size: 1.5rem;
                    color: $text-light;
                }
            }

            span {
                font-family: $font-primary;
                font-size: 1.5rem;
                font-weight: 700;
                @include gradient-text;
            }
        }

        p {
