                border-radius: 2px;
            }
        }

        ul {
            list-style: none;
            padding: 0;

            li {
                margin-bottom: 12px;

                a {
                    color: $text-muted;
                    display: flex;
                    align-items: center;

                    i {
                        margin-right: 10px;
                        color: $primary-color;
