    }

    .footer-bottom {
        border-top: 1px solid rgba($primary-color, 0.1);
        padding: 25px 0;
        margin-top: 40px;

        p {
            margin: 0;
            color: $text-muted;
        }

        .footer-links {
            display: flex;
            gap: 25px;
