// ==========================================
// BACK TO TOP
// ==========================================
.back-to-top {
    position: fixed;
    bottom: 30px;
    right: 30px;
    width: 50px;
    height: 50px;
    background: $gradient-primary;
    border-radius: 50%;
    @include flex-center;
    color: $text-light;
    font-size: 1.25rem;
    opacity: 0;
    visibility: hidden;
    transition: $transition;
    z-index: 999;
    cursor: pointer;

    &.show {
        opacity: 1;
        visibility: visible;
    }

    &:hover {
        transform: translateY(-5px);
        @include glow-effect($primary-color);
    }
}

// ==========================================
// PAGE HEADER
// ==========================================
.page-header {
    background: linear-gradient(135deg, rgba($primary-color, 0.1) 0%, rgba($secondary-color, 0.1) 100%);
    padding: 150px 0 80px;
    text-align: center;
    position: relative;

    &::before {
        content: '';
        position: absolute;
        top: 0;
        left: 0;
        width: 100%;
        height: 100%;
        background: url('data:image/svg+xml,<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 100 100"><circle cx="50" cy="50" r="40" fill="none" stroke="rgba(139,92,246,0.1)" stroke-width="0.5"/></svg>');
