                margin: 0;
                font-size: 1rem;
            }

            i {
                color: $primary-color;
                transition: $transition;
            }
        }

        .faq-answer {
            padding: 0 25px 20px;
            display: none;

            p {
                margin: 0;
            }
        }
    }
}

// ==========================================
// TEAM SECTION
// ==========================================
.team-section {
    .team-card {
        background: $bg-card;
        border-radius: $border-radius-lg;
        overflow: hidden;
        border: 1px solid rgba($primary-color, 0.1);
