                height: 280px;
                object-fit: cover;
                transition: $transition;
            }
        }

        .team-info {
            padding: 25px;
            text-align: center;

            h4 {
                margin-bottom: 5px;
            }

            span {
                color: $primary-color;
                font-size: 0.875rem;
            }

            .social-links {
                display: flex;
                justify-content: center;
                gap: 10px;
                margin-top: 15px;

                a {
