/* ============================================
   AIFORGE v2.5
   Theme Name: AIForge
   Version: 2.5 (Premium Glassmorphism Edition)
   Style: Future Reality / Haptic Light
   Author: Nexus Team
   ============================================ */

/* ============================================
   FONTS & IMPORTS
   ============================================ */
@import url('https://fonts.googleapis.com/css2?family=Plus+Jakarta+Sans:wght@300;400;500;600;700&family=Space+Grotesk:wght@300;400;500;600;700&display=swap');

/* ============================================
      CSS VARIABLES (HOLOGRAPHIC SYSTEM)
      ============================================ */
:root {
    /* Core Palette - Iridescent */
    --af-primary: #8b5cf6;
    /* Electric Purple */
    --af-secondary: #ec4899;
    /* Cyber Pink */
    --af-accent: #06b6d4;
    /* Holographic Cyan */
    --af-dark: #0f172a;

    /* Backgrounds */
    --af-bg-light: #f8fafc;
    --af-bg-white: #ffffff;
    --af-bg-glass: rgba(255, 255, 255, 0.7);
    /* Slightly increased opacity for better contrast */
    --af-bg-glass-strong: rgba(255, 255, 255, 0.90);
    --af-bg-dark-glass: rgba(15, 23, 42, 0.85);

    /* Typography */
    --font-display: 'Space Grotesk', sans-serif;
    --font-body: 'Plus Jakarta Sans', sans-serif;

    /* Effects - Glassmorphism 2.0 Enhanced */
    --af-blur: 32px;
    /* Increased blur for smoother glass */
    --af-border-light: 1px solid rgba(255, 255, 255, 0.65);
    --af-border-shadow: 1px solid rgba(255, 255, 255, 0.25);

    /* Ambient Shadows (Colored & Deep) */
    --af-shadow-ambient:
        0 20px 40px -10px rgba(139, 92, 246, 0.12),
        0 0 0 1px rgba(255, 255, 255, 0.6) inset;

    --af-shadow-hover:
        0 30px 60px -12px rgba(139, 92, 246, 0.3),
        0 0 0 1px rgba(255, 255, 255, 0.9) inset;

    --af-gradient-holo: linear-gradient(135deg, #8b5cf6, #ec4899, #06b6d4);
    --af-gradient-text: linear-gradient(to right, #7c3aed, #db2777);

    /* 3D Specs */
    --af-perspective: 1200px;
    --af-ease: cubic-bezier(0.22, 1, 0.36, 1);
}

/* ============================================
      RESET & BASE
      ============================================ */
*,
*::before,
*::after {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
}

html {
    scroll-behavior: auto;
    height: 100%;
    overflow-x: hidden;
}

body {
    background-color: var(--af-bg-light);
    color: #334155;
    font-family: var(--font-body);
    font-size: 17px;
    line-height: 1.7;
    overflow-x: hidden;
    overflow-y: auto;
    width: 100%;
    min-height: 100vh;
    height: 100%;
    position: relative;
    perspective: var(--af-perspective);
    text-rendering: optimizeLegibility;
    -webkit-font-smoothing: antialiased;
}

/* Ambient Gradient Mesh Background (Softer) */
body::before {
    content: '';
    position: fixed;
    top: -50%;
    left: -50%;
    width: 200%;
    height: 200%;
    background:
        radial-gradient(circle at 50% 50%, rgba(139, 92, 246, 0.05), transparent 60%),
        radial-gradient(circle at 10% 20%, rgba(6, 182, 212, 0.05), transparent 50%),
        radial-gradient(circle at 90% 80%, rgba(236, 72, 153, 0.05), transparent 50%);
    z-index: -1;
    animation: ambient-drift 25s infinite linear;
    pointer-events: none;
    transform-origin: center center;
}

@keyframes ambient-drift {
    from {
        transform: rotate(0deg) scale(1);
    }

    to {
        transform: rotate(360deg) scale(1);
    }
}

/* Global Animation */
@keyframes fadeInUp {
    from {
        opacity: 0;
        transform: translateY(20px);
    }

    to {
        opacity: 1;
        transform: translateY(0);
    }
}

.fade-in-up {
    animation: fadeInUp 0.8s var(--af-ease) forwards;
}

h1,
h2,
h3,
h4,
h5,
h6 {
    font-family: var(--font-display);
    color: var(--af-dark);
    font-weight: 700;
    letter-spacing: -0.04em;
    line-height: 1.1;
}

h1 {
    font-size: clamp(3rem, 5vw, 5.5rem);
    letter-spacing: -0.05em;
    text-shadow: 0 10px 30px rgba(0, 0, 0, 0.1);
}

h2 {
    font-size: clamp(2.2rem, 3.5vw, 3.5rem);
    letter-spacing: -0.03em;
}

p {
    margin-bottom: 1.5rem;
    font-weight: 400;
    color: #475569;
    /* Slightly darker for better contrast */
}

a {
    text-decoration: none;
    color: inherit;
    transition: all 0.3s var(--af-ease);
}

ul {
    list-style: none;
}

.af-container {
