/* ============================================
      PAGE HEADERS (Internal Pages)
      ============================================ */
header {
    position: relative;
    padding: 200px 0 100px;
    text-align: center;
    background: linear-gradient(180deg, #f8fafc 0%, #f1f5f9 100%);
    overflow: hidden;
    z-index: 1;
}

header::before {
    content: '';
    position: absolute;
    top: -50%;
    left: -50%;
    width: 200%;
    height: 200%;
    background:
        radial-gradient(circle at 30% 20%, rgba(139, 92, 246, 0.08), transparent 40%),
        radial-gradient(circle at 70% 80%, rgba(6, 182, 212, 0.08), transparent 40%);
    animation: ambient-drift 20s infinite linear;
    pointer-events: none;
    z-index: -1;
}

header .af-container {
    position: relative;
    z-index: 2;
}

header h1 {
    animation: fadeInUp 0.8s var(--af-ease) forwards;
}

header p {
    animation: fadeInUp 1s var(--af-ease) 0.2s forwards;
