/* Text Effects */
.text-gradient {
    background: var(--af-gradient-text) !important;
    -webkit-background-clip: text !important;
    background-clip: text !important;
    -webkit-text-fill-color: transparent !important;
    color: transparent !important;
    display: inline-block;
}

/* GLASS PANEL 2.0 (The Star of the Show) */
.glass-panel {
    background: var(--af-bg-glass);
    backdrop-filter: blur(var(--af-blur));
    -webkit-backdrop-filter: blur(var(--af-blur));
    border-radius: 24px;

    /* Enhanced Light Source logic - Darker borders for visibility on light bg */
    border-top: 1px solid rgba(255, 255, 255, 0.9);
    border-left: 1px solid rgba(255, 255, 255, 0.9);
    border-bottom: 1px solid rgba(200, 200, 200, 0.4);
    /* Darker shadow border */
    border-right: 1px solid rgba(200, 200, 200, 0.4);
    /* Darker shadow border */

    box-shadow:
        0 4px 24px -1px rgba(0, 0, 0, 0.05),
        /* Base shadow */
        0 0 0 1px rgba(255, 255, 255, 0.6) inset;
    /* Inner bevel */
    transition: all 0.5s var(--af-ease);
    position: relative;
    overflow: hidden;
}

/* Darker text for glass panels to ensure readability */
.glass-panel h1,
.glass-panel h2,
.glass-panel h3,
.glass-panel h4,
.glass-panel h5,
.glass-panel h6 {
    color: #1e293b;
}

.glass-panel p,
.glass-panel li,
.glass-panel span {
    color: #475569;
}

.glass-panel::before {
    content: '';
    position: absolute;
    top: 0;
    left: -100%;
    width: 200%;
    height: 100%;
    background: linear-gradient(115deg,
            transparent 0%,
            rgba(255, 255, 255, 0.4) 40%,
            rgba(255, 255, 255, 0.4) 60%,
            transparent 100%);
    transform: skewX(-20deg);
    transition: 0.7s;
    pointer-events: none;
    opacity: 0;
}

.glass-panel:hover {
    transform: translateY(-5px) scale(1.005);
    box-shadow: var(--af-shadow-hover);
    background: rgba(255, 255, 255, 0.8);
    border-color: #fff;
}

.glass-panel:hover::before {
    left: 100%;
    opacity: 0.15;
    transition: 0.7s;
}

/* Dark Glass Variant */
.glass-panel-dark {
    background: var(--af-bg-dark-glass);
    backdrop-filter: blur(var(--af-blur));
    -webkit-backdrop-filter: blur(var(--af-blur));
    border-radius: 24px;
    border: 1px solid rgba(255, 255, 255, 0.15);
    box-shadow: 0 15px 40px rgba(0, 0, 0, 0.4);
