      RESPONSIVE ADJUSTMENTS
      ============================================ */
/* ============================================
      ADDITIONAL PAGE COMPONENTS
      ============================================ */

/* Section Spacing */
section {
    position: relative;
}

/* Page Content Wrapper */
.page-content {
    padding: 80px 0;
    background: #f8fafc;
}

/* Stats/Numbers Display */
.stat-box {
    text-align: center;
    padding: 40px 30px;
    background: rgba(255, 255, 255, 0.6);
    backdrop-filter: blur(20px);
    border-radius: 24px;
    border: 1px solid rgba(255, 255, 255, 0.8);
    transition: all 0.4s var(--af-ease);
}

.stat-box:hover {
    transform: translateY(-10px);
    box-shadow: 0 20px 40px -10px rgba(139, 92, 246, 0.2);
    background: rgba(255, 255, 255, 0.9);
}

.stat-box h3 {
    font-size: 3.5rem;
    background: var(--af-gradient-text);
    -webkit-background-clip: text;
    background-clip: text;
    -webkit-text-fill-color: transparent;
    margin-bottom: 10px;
}

.stat-box p {
    color: #64748b;
    font-weight: 600;
    margin: 0;
    text-transform: uppercase;
    letter-spacing: 1px;
    font-size: 0.9rem;
}

/* Feature List */
.feature-list {
    list-style: none;
    padding: 0;
    margin: 30px 0;
}

.feature-list li {
    padding: 15px 0;
    padding-left: 40px;
    position: relative;
    color: #475569;
    font-size: 1.1rem;
    border-bottom: 1px solid rgba(0, 0, 0, 0.05);
}

.feature-list li:last-child {
    border-bottom: none;
}

.feature-list li::before {
    content: '\2713';
    position: absolute;
    left: 0;
    top: 50%;
    transform: translateY(-50%);
    width: 28px;
    height: 28px;
    background: var(--af-gradient-holo);
    color: white;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: bold;
    font-size: 0.9rem;
}

/* Image Containers with Effects */
.image-glow {
    position: relative;
    border-radius: 24px;
    overflow: hidden;
}

.image-glow::before {
    content: '';
    position: absolute;
    inset: -50%;
    background: radial-gradient(circle, rgba(139, 92, 246, 0.3), transparent 70%);
    filter: blur(30px);
    z-index: -1;
    animation: pulse-glow 3s ease-in-out infinite;
}

.image-glow img {
    width: 100%;
    height: auto;
    display: block;
    border-radius: 24px;
}

/* Pricing Cards Enhancement */
.pricing-card {
    background: var(--af-bg-glass);
    backdrop-filter: blur(var(--af-blur));
    border-radius: 32px;
    padding: 50px 40px;
    border: 1px solid rgba(255, 255, 255, 0.6);
    box-shadow: var(--af-shadow-ambient);
    transition: all 0.5s var(--af-ease);
    position: relative;
    overflow: hidden;
}

.pricing-card::before {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    height: 5px;
    background: var(--af-gradient-holo);
    transform: scaleX(0);
    transition: transform 0.5s var(--af-ease);
}

.pricing-card:hover::before {
    transform: scaleX(1);
}

.pricing-card:hover {
    transform: translateY(-15px) scale(1.02);
    box-shadow: 0 30px 60px -15px rgba(139, 92, 246, 0.3);
    border-color: var(--af-primary);
}

.pricing-card.featured {
    background: linear-gradient(135deg, rgba(139, 92, 246, 0.1), rgba(6, 182, 212, 0.1));
    border: 2px solid var(--af-primary);
}

/* Team Member Cards */
.team-card {
    text-align: center;
    padding: 40px 30px;
    background: var(--af-bg-glass);
    backdrop-filter: blur(20px);
    border-radius: 24px;
    border: 1px solid rgba(255, 255, 255, 0.6);
    transition: all 0.4s var(--af-ease);
}

.team-card:hover {
    transform: translateY(-10px);
    box-shadow: 0 20px 50px -10px rgba(139, 92, 246, 0.25);
}

.team-card img {
    width: 120px;
    height: 120px;
    border-radius: 50%;
    margin-bottom: 20px;
    border: 4px solid white;
    box-shadow: 0 10px 25px rgba(0, 0, 0, 0.1);
}

.team-card h4 {
    margin-bottom: 8px;
    font-size: 1.3rem;
}

.team-card p {
    color: #64748b;
    margin-bottom: 20px;
    font-size: 0.95rem;
}

.team-card .social-links {
    display: flex;
    justify-content: center;
    gap: 15px;
}

.team-card .social-links a {
    width: 40px;
    height: 40px;
    display: flex;
    align-items: center;
    justify-content: center;
    border-radius: 50%;
    background: rgba(139, 92, 246, 0.1);
    color: var(--af-primary);
    transition: all 0.3s var(--af-ease);
}

.team-card .social-links a:hover {
    background: var(--af-primary);
    color: white;
    transform: translateY(-3px);
}

@media (max-width: 992px) {
    .cards-3d-grid {
        grid-template-columns: 1fr;
    }

    .hero-title {
        font-size: 3rem;
    }

    .hero-card {
