        padding: 150px 0 80px;
    }

    header h1 {
        font-size: 2.5rem !important;
    }

    .stat-box h3 {
        font-size: 2.5rem;
    }

    /* Mobile Menu Overlay */
    .af-menu-wrapper {
        position: fixed;
        top: 80px;
        left: 0;
        width: 100%;
        height: calc(100vh - 80px);
        background: rgba(255, 255, 255, 0.98);
        backdrop-filter: blur(20px);
        flex-direction: column;
        align-items: flex-start;
        padding: 40px 20px;
        gap: 0;
        display: none;
        overflow-y: auto;
    }

    .af-menu-wrapper.active {
        display: flex;
    }

    .af-menu {
        flex-direction: column;
        width: 100%;
        gap: 0;
        align-items: flex-start;
    }

    .af-link {
        width: 100%;
        padding: 20px 0;
        border-bottom: 1px solid rgba(0, 0, 0, 0.05);
        font-size: 1.2rem;
    }

    .af-dropdown {
        flex-direction: column;
        align-items: flex-start;
        width: 100%;
    }

    .af-dropdown-menu {
        position: static;
        width: 100%;
        transform: none;
        opacity: 1;
        visibility: visible;
        background: transparent;
        box-shadow: none;
        border: none;
        padding: 0 0 0 20px;
        display: none;
    }

    .af-dropdown:hover .af-dropdown-menu {
        display: flex;
    }

    .af-nav-icons {
        margin: 40px 0;
        width: 100%;
        justify-content: center;
    }

    .btn-af.ms-4 {
        margin-left: 0 !important;
        width: 100%;
    }
}

/* ============================================
   ENHANCED SERVICE PAGES
   ============================================ */

/* Service Cards Enhanced */
.card-3d {
    position: relative;
    overflow: hidden;
    border-radius: 32px;
    cursor: pointer;
    transition: all 0.6s cubic-bezier(0.23, 1, 0.32, 1);
}

.card-3d::before {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background: linear-gradient(135deg, rgba(139, 92, 246, 0.1), rgba(6, 182, 212, 0.1));
    opacity: 0;
    transition: opacity 0.6s var(--af-ease);
    z-index: 1;
}

.card-3d:hover::before {
    opacity: 1;
}

.card-3d::after {
    content: '';
    position: absolute;
    top: 50%;
    left: 50%;
    width: 0;
    height: 0;
    background: radial-gradient(circle, rgba(255, 255, 255, 0.8), transparent);
    border-radius: 50%;
    transform: translate(-50%, -50%);
    transition: all 0.6s var(--af-ease);
    opacity: 0;
    z-index: 2;
    pointer-events: none;
}

.card-3d:hover::after {
    width: 300%;
    height: 300%;
    opacity: 0.1;
}

.card-3d .card-3d-bg {
    transition: transform 0.6s var(--af-ease), filter 0.6s var(--af-ease);
}

.card-3d:hover .card-3d-bg {
    transform: scale(1.1);
    filter: brightness(1.2);
}

.card-3d .card-3d-content {
    position: relative;
    z-index: 3;
    transition: transform 0.6s var(--af-ease);
}

.card-3d:hover .card-3d-content {
    transform: translateY(-10px);
}

.card-3d .card-3d-content h3 {
    font-family: var(--font-display);
    font-weight: 700;
    font-size: 2rem;
    margin-bottom: 15px;
    transition: all 0.3s var(--af-ease);
}

.card-3d:hover .card-3d-content h3 {
    letter-spacing: 1px;
}

.card-3d .card-3d-content p {
    font-size: 1.05rem;
    line-height: 1.6;
    margin-bottom: 20px;
}

.card-3d .card-3d-content i {
    transition: all 0.5s var(--af-ease);
    display: inline-block;
}

.card-3d:hover .card-3d-content i {
    transform: scale(1.15) rotate(5deg);
}

.card-3d .card-3d-content .btn-af {
    transform: translateY(0);
    opacity: 1;
    transition: all 0.4s var(--af-ease);
}

.card-3d:hover .card-3d-content .btn-af {
    transform: translateY(-5px);
    box-shadow: 0 15px 35px rgba(139, 92, 246, 0.3);
}

/* Animated Gradient Background for Cards */
@keyframes gradient-shift {

    0%,
    100% {
        background-position: 0% 50%;
    }

    50% {
        background-position: 100% 50%;
    }
}

.card-3d .card-3d-bg[style*="linear-gradient"] {
    background-size: 200% 200%;
    animation: gradient-shift 15s ease infinite;
}

/* Service Single Page Enhancements */
.col-lg-8 .glass-panel {
    transition: all 0.5s var(--af-ease);
    position: relative;
    overflow: hidden;
}

.col-lg-8 .glass-panel::before {
    content: '';
    position: absolute;
    top: -50%;
    left: -50%;
    width: 200%;
    height: 200%;
    background: radial-gradient(circle, rgba(139, 92, 246, 0.05), transparent 70%);
    animation: ambient-drift 20s infinite linear;
    pointer-events: none;
    z-index: 0;
}

.col-lg-8 .glass-panel>* {
    position: relative;
    z-index: 1;
}

.col-lg-8 .glass-panel:hover {
    transform: translateY(-5px);
    box-shadow: 0 25px 50px -12px rgba(139, 92, 246, 0.2);
}

.col-lg-8 .glass-panel img {
    transition: all 0.6s var(--af-ease);
    display: block;
}

.col-lg-8 .glass-panel:hover img {
    transform: scale(1.05);
    filter: brightness(1.1);
}

/* Service Details Sidebar */
.col-lg-4 .glass-panel {
    transition: all 0.4s var(--af-ease);
    position: relative;
    overflow: hidden;
}

.col-lg-4 .glass-panel::before {
    content: '';
    position: absolute;
    top: 0;
    left: -100%;
    width: 100%;
    height: 100%;
    background: linear-gradient(90deg, transparent, rgba(139, 92, 246, 0.1), transparent);
    transition: all 0.6s var(--af-ease);
}

.col-lg-4 .glass-panel:hover::before {
    left: 100%;
}

.col-lg-4 .glass-panel:hover {
    transform: translateX(-5px);
    box-shadow: 0 20px 40px -10px rgba(139, 92, 246, 0.25);
}

.col-lg-4 .glass-panel h4 {
    font-family: var(--font-display);
    font-weight: 700;
    color: var(--af-dark);
    margin-bottom: 25px;
    padding-bottom: 15px;
    border-bottom: 2px solid rgba(139, 92, 246, 0.2);
}

.col-lg-4 .glass-panel .border-bottom {
    border-color: rgba(0, 0, 0, 0.08) !important;
    transition: all 0.3s var(--af-ease);
}

.col-lg-4 .glass-panel .border-bottom:hover {
    border-color: rgba(139, 92, 246, 0.3) !important;
    padding-left: 10px;
}

/* Check Icons Enhancement */
.fa-check {
    width: 20px;
    height: 20px;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    background: var(--af-gradient-holo);
    color: white;
    border-radius: 50%;
    font-size: 0.7rem;
}

/* Tech Stack Box */
.rounded-3[style*="background: rgba(0,0,0,0.03)"] {
    transition: all 0.4s var(--af-ease);
    border-left: 4px solid transparent;
}

.rounded-3[style*="background: rgba(0,0,0,0.03)"]:hover {
    background: rgba(139, 92, 246, 0.05) !important;
    border-left-color: var(--af-primary);
    transform: translateX(10px);
}

/* Other Solutions List */
.list-unstyled a {
    display: flex;
    align-items: center;
    padding: 12px 15px;
    border-radius: 12px;
    transition: all 0.3s var(--af-ease);
    position: relative;
    overflow: hidden;
}

.list-unstyled a::before {
    content: '';
    position: absolute;
    left: 0;
    top: 50%;
    transform: translateY(-50%);
    width: 3px;
    height: 0;
    background: var(--af-gradient-holo);
    transition: all 0.3s var(--af-ease);
}

.list-unstyled a:hover::before {
    height: 100%;
}

.list-unstyled a:hover {
    background: rgba(139, 92, 246, 0.05);
    color: var(--af-primary) !important;
    transform: translateX(10px);
}

.list-unstyled a i {
    transition: all 0.3s var(--af-ease);
}

.list-unstyled a:hover i {
    transform: translateX(5px);
    color: var(--af-primary);
}

/* Hover Primary Utility */
.hover-primary {
    transition: all 0.3s var(--af-ease);
}

.hover-primary:hover {
    color: var(--af-primary) !important;
}

/* Service Page Header Enhancement - Removed to prevent visual glitches */

/* Header Cleanup - Remove all pseudo elements from headers */
header::before,
header::after,
header h1::before,
header h1::after,
header h2::before,
header h2::after,
header span::before,
header span::after {
    display: none !important;
    content: none !important;
    background: none !important;
    width: 0 !important;
    height: 0 !important;
}

