/* Card 3D Grid Layout */
.cards-3d-grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(380px, 1fr));
    gap: 35px;
    margin-top: 60px;
}

/* Default Card Height */
.cards-3d-grid .card-3d {
    height: 450px;
    position: relative;
}

/* Card 3D Background - Full Size */
.card-3d .card-3d-bg {
    position: absolute;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    z-index: 0;
}

/* Card Content Positioning */
.card-3d .card-3d-content {
    position: absolute;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    padding: 45px;
    display: flex;
    flex-direction: column;
    justify-content: center;
    z-index: 1;
}

/* Card Title Styling */
.card-3d .card-3d-content h3 {
    font-size: 2.2rem;
    margin-bottom: 15px;
    font-weight: 700;
}

.card-3d .card-3d-content p {
    font-size: 1.05rem;
    line-height: 1.7;
}

/* Image Enhancement */
.glass-panel img {
    border-radius: 0;
    object-fit: cover;
}

.overflow-hidden {
    overflow: hidden !important;
}

/* Grid Gap Enhancement */
.g-5 {
    margin: -24px;
}

.g-5>* {
    padding: 24px;
}

.row.g-5 {
    --bs-gutter-x: 3rem;
    --bs-gutter-y: 3rem;
}

/* Button Full Width */
.w-100 {
    width: 100% !important;
}

/* Text Small */
.text-sm {
    font-size: 0.95rem;
}

/* Floating Animation for Icons */
@keyframes float-icon {

    0%,
    100% {
        transform: translateY(0);
    }

    50% {
        transform: translateY(-10px);
    }
}

.card-3d .text-gradient {
    animation: float-icon 3s ease-in-out infinite;
}

