// ==========================================
// TIPOGRAFIA
// ==========================================
$font-primary: 'Plus Jakarta Sans', -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
$font-display: 'Space Grotesk', -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;

$font-size-base: 1rem;
$font-size-sm: 0.875rem;
$font-size-lg: 1.125rem;
$font-size-xl: 1.25rem;
$font-size-2xl: 1.5rem;
$font-size-3xl: 1.875rem;
$font-size-4xl: 2.25rem;
$font-size-5xl: 3rem;

$font-weight-light: 300;
$font-weight-normal: 400;
$font-weight-medium: 500;
$font-weight-semibold: 600;
$font-weight-bold: 700;
$font-weight-extrabold: 800;

$line-height-tight: 1.25;
$line-height-normal: 1.5;
$line-height-relaxed: 1.75;
$line-height-loose: 2;

// ==========================================
// ESPAÇAMENTO
// ==========================================
$spacing-xs: 0.25rem;    // 4px
$spacing-sm: 0.5rem;     // 8px
$spacing-md: 1rem;       // 16px
$spacing-lg: 1.5rem;     // 24px
$spacing-xl: 2rem;       // 32px
$spacing-2xl: 3rem;      // 48px
$spacing-3xl: 4rem;      // 64px
$spacing-4xl: 6rem;      // 96px
$spacing-5xl: 8rem;      // 128px

// ==========================================
// BORDER RADIUS
// ==========================================
$radius-sm: 0.25rem;     // 4px
$radius-md: 0.5rem;      // 8px
$radius-lg: 1rem;        // 16px
$radius-xl: 1.5rem;      // 24px
$radius-2xl: 2rem;       // 32px
$radius-full: 9999px;

// ==========================================
// SOMBRAS
// ==========================================
$shadow-sm: 0 1px 2px 0 rgba(0, 0, 0, 0.05);
$shadow-md: 0 4px 6px -1px rgba(0, 0, 0, 0.1), 0 2px 4px -1px rgba(0, 0, 0, 0.06);
$shadow-lg: 0 10px 15px -3px rgba(0, 0, 0, 0.1), 0 4px 6px -2px rgba(0, 0, 0, 0.05);
$shadow-xl: 0 20px 25px -5px rgba(0, 0, 0, 0.1), 0 10px 10px -5px rgba(0, 0, 0, 0.04);
$shadow-2xl: 0 25px 50px -12px rgba(0, 0, 0, 0.25);
$shadow-glass: 0 8px 32px 0 rgba(31, 38, 135, 0.15);

// ==========================================
// GLASSMORPHISM
// ==========================================
$glass-bg: rgba(255, 255, 255, 0.85);
$glass-border: rgba(255, 255, 255, 0.3);
$glass-backdrop: blur(10px);

// ==========================================
// TRANSIÇÕES E ANIMAÇÕES
// ==========================================
$transition-fast: 0.15s;
$transition-base: 0.3s;
$transition-slow: 0.5s;
$ease-default: cubic-bezier(0.4, 0, 0.2, 1);
$ease-in: cubic-bezier(0.4, 0, 1, 1);
$ease-out: cubic-bezier(0, 0, 0.2, 1);
$ease-in-out: cubic-bezier(0.4, 0, 0.2, 1);
$ease-custom: cubic-bezier(0.34, 1.56, 0.64, 1);

// ==========================================
// BREAKPOINTS
// ==========================================
$breakpoint-xs: 0;
$breakpoint-sm: 576px;
$breakpoint-md: 768px;
$breakpoint-lg: 992px;
$breakpoint-xl: 1200px;
$breakpoint-xxl: 1400px;

// ==========================================
// Z-INDEX
// ==========================================
$z-dropdown: 1000;
$z-sticky: 1020;
$z-fixed: 1030;
$z-modal-backdrop: 1040;
$z-modal: 1050;
$z-popover: 1060;
$z-tooltip: 1070;

// ==========================================
// NAVBAR
// ==========================================
$navbar-height: 80px;
$navbar-bg: $glass-bg;
$navbar-scrolled-bg: rgba(255, 255, 255, 0.95);
$navbar-padding-y: 1.25rem;
$navbar-padding-x: 2rem;

// ==========================================
// CARDS 3D
// ==========================================
$card-3d-padding: 2.5rem;
$card-3d-radius: 1.5rem;
$card-3d-shadow: 0 20px 40px rgba(0, 0, 0, 0.1);
$card-3d-hover-lift: -10px;
$card-3d-transition: 0.4s;

// ==========================================
// BADGES
// ==========================================
$badge-padding-y: 0.5rem;
$badge-padding-x: 1rem;
$badge-radius: 1.5rem;
$badge-font-size: 0.75rem;

/* ═══════════════════════════════════════════════════════════════════════════
   AURORA DIGITAL - BLUE & PINK LIGHT MODE DESIGN SYSTEM
   Premium Light Mode Template with Elegant Minimalist Design
   ═══════════════════════════════════════════════════════════════════════════ */

/* ─────────────────────────────────────────────────────────────────────────────
   CSS VARIABLES - DESIGN TOKENS
   ───────────────────────────────────────────────────────────────────────────── */
:root {
    /* Primary Color Palette - Blue & Pink */
    --primary: #3b82f6;
    --primary-light: #60a5fa;
    --primary-dark: #2563eb;
    --secondary: #ec4899;
    --secondary-light: #f472b6;
    --secondary-dark: #db2777;
    --accent: #8b5cf6;
    --accent-light: #a78bfa;

    /* Light Theme Backgrounds */
    --bg-primary: #ffffff;
    --bg-secondary: #f8fafc;
    --bg-tertiary: #f1f5f9;
    --bg-card: #ffffff;

    /* Text Colors */
    --text-primary: #0f172a;
    --text-secondary: #475569;
    --text-muted: #94a3b8;

    /* Glassmorphism - Light Version */
    --glass-bg: rgba(255, 255, 255, 0.7);
    --glass-bg-hover: rgba(255, 255, 255, 0.9);
    --glass-border: rgba(0, 0, 0, 0.05);
    --glass-border-hover: rgba(0, 0, 0, 0.1);
    --blur-amount: 20px;

    /* Gradients */
    --gradient-primary: linear-gradient(135deg, var(--primary), var(--secondary));
    --gradient-hover: linear-gradient(135deg, var(--primary-light), var(--secondary-light));
    --gradient-subtle: linear-gradient(180deg, var(--bg-primary) 0%, var(--bg-secondary) 100%);
    --gradient-radial: radial-gradient(ellipse at 50% 0%, rgba(59, 130, 246, 0.08) 0%, transparent 50%);

    /* Shadows - Soft & Elegant (Refined) */
    --shadow-sm: 0 2px 4px rgba(148, 163, 184, 0.1);
    --shadow-card: 0 10px 30px -5px rgba(148, 163, 184, 0.15);
    --shadow-elevated: 0 20px 40px -5px rgba(148, 163, 184, 0.2);
    --shadow-glow: 0 0 50px rgba(59, 130, 246, 0.25);

    /* Typography */
    --font-heading: 'Inter', sans-serif;
    --font-body: 'Inter', sans-serif;

    /* Spacing & Sizing */
    --section-padding: 120px;
    /* Increased for better breathing room */
    --container-max: 1280px;
    --border-radius: 12px;
    --border-radius-sm: 6px;
    --border-radius-lg: 20px;
    --border-radius-full: 9999px;

    /* Transitions */
    --transition-fast: 0.2s cubic-bezier(0.4, 0, 0.2, 1);
    --transition-base: 0.3s cubic-bezier(0.4, 0, 0.2, 1);
    --transition-slow: 0.5s cubic-bezier(0.4, 0, 0.2, 1);
}

/* ─────────────────────────────────────────────────────────────────────────────
   BASE RESET & GLOBAL STYLES
   ───────────────────────────────────────────────────────────────────────────── */
*,
*::before,
*::after {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
}

html {
    scroll-behavior: smooth;
    font-size: 16px;
}

body {
    font-family: var(--font-body);
    font-size: 1rem;
    line-height: 1.7;
    color: var(--text-secondary);
    background: var(--bg-primary);
    overflow-x: hidden;
    -webkit-font-smoothing: antialiased;
}

/* Subtle Pattern Overlay */
body::before {
    content: '';
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background-image: radial-gradient(circle at 1px 1px, rgba(59, 130, 246, 0.03) 1px, transparent 0);
    background-size: 40px 40px;
    pointer-events: none;
    z-index: -1;
}

/* ─────────────────────────────────────────────────────────────────────────────
   TYPOGRAPHY
   ───────────────────────────────────────────────────────────────────────────── */
h1,
h2,
h3,
h4,
h5,
h6 {
    font-family: var(--font-heading);
    font-weight: 700;
    color: var(--text-primary);
    line-height: 1.3;
    margin-bottom: 1rem;
}

h1 {
    font-size: clamp(2.25rem, 5vw, 3.5rem);
}

h2 {
    font-size: clamp(1.75rem, 3.5vw, 2.5rem);
}

h3 {
    font-size: clamp(1.25rem, 2.5vw, 1.75rem);
}

h4 {
    font-size: 1.125rem;
}

h5 {
    font-size: 1rem;
}

h6 {
    font-size: 0.875rem;
}

p {
    margin-bottom: 1.5rem;
    color: var(--text-secondary);
}

a {
    color: var(--primary);
    text-decoration: none;
    transition: var(--transition-base);
}

a:hover {
    color: var(--secondary);
}

/* Gradient Text */
.gradient-text {
    background: var(--gradient-primary);
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    background-clip: text;
}

/* ─────────────────────────────────────────────────────────────────────────────
   LAYOUT UTILITIES
   ───────────────────────────────────────────────────────────────────────────── */
.container {
    width: 100%;
    max-width: var(--container-max);
    margin: 0 auto;
    padding: 0 1.5rem;
}

.section-padding {
    padding: var(--section-padding) 0;
}

.section-header {
    text-align: center;
    max-width: 600px;
    margin: 0 auto 4rem;
}

.section-header .subtitle {
    display: inline-flex;
    align-items: center;
    gap: 0.5rem;
    padding: 0.5rem 1rem;
    font-size: 0.75rem;
    font-weight: 600;
    text-transform: uppercase;
    letter-spacing: 2px;
    color: var(--primary);
    background: rgba(59, 130, 246, 0.08);
    border-radius: var(--border-radius-full);
    margin-bottom: 1rem;
}

.section-header .subtitle::before {
    content: '';
    width: 6px;
    height: 6px;
    background: var(--gradient-primary);
    border-radius: 50%;
}

/* ─────────────────────────────────────────────────────────────────────────────
   TOP BAR
   ───────────────────────────────────────────────────────────────────────────── */
.page-header-aurora {
    padding: 160px 0 80px;
    background: var(--bg-secondary);
    position: relative;
    overflow: visible;
    /* Ensure content isn't clipped */
}

.page-header-aurora h1 {
    margin-bottom: 1rem;
    line-height: 1.2;
    padding-bottom: 10px;
    /* Extra space for descenders */
    background: var(--bg-secondary);
    /* Fix for potential z-index issues */
}

.top-bar {
    background: var(--bg-tertiary);
    padding: 0.75rem 0;
    font-size: 0.85rem;
    border-bottom: 1px solid var(--glass-border);
}

.top-bar-content {
    display: flex;
    justify-content: space-between;
    align-items: center;
}

.top-bar-left {
    display: flex;
    gap: 2rem;
}

.top-bar-left a,
.top-bar-left span {
    color: var(--text-secondary);
    display: flex;
    align-items: center;
    gap: 0.5rem;
}

.top-bar-left a:hover {
    color: var(--primary);
}

.top-bar-left i {
    color: var(--primary);
}

.top-bar-right {
    display: flex;
    gap: 0.75rem;
}

.top-bar-right a {
    color: var(--text-muted);
    width: 32px;
    height: 32px;
    display: flex;
    align-items: center;
    justify-content: center;
    background: var(--bg-primary);
    border-radius: 50%;
    transition: var(--transition-base);
}

.top-bar-right a:hover {
    color: var(--bg-primary);
    background: var(--gradient-primary);
}

/* ─────────────────────────────────────────────────────────────────────────────
   NAVIGATION
   ───────────────────────────────────────────────────────────────────────────── */
.main-nav {
    position: fixed;
    top: 0;
    left: 0;
    right: 0;
    z-index: 1000;
    padding: 1rem 0;
    background: rgba(255, 255, 255, 0.9);
    backdrop-filter: blur(var(--blur-amount));
    -webkit-backdrop-filter: blur(var(--blur-amount));
    border-bottom: 1px solid var(--glass-border);
    transition: var(--transition-base);
}

.main-nav.scrolled {
    padding: 0.75rem 0;
    box-shadow: var(--shadow-card);
}

.main-nav .container {
    display: flex;
    align-items: center;
    justify-content: space-between;
}

.navbar-brand {
    font-family: var(--font-heading);
    font-size: 1.5rem;
    font-weight: 800;
    color: var(--text-primary) !important;
}

.navbar-brand span {
    background: var(--gradient-primary);
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    background-clip: text;
}

.navbar-collapse {
    display: flex !important;
    flex-direction: row;
    align-items: center;
    flex: 1;
    justify-content: center;
    position: relative;
}

.nav-menu {
    display: flex;
    flex-direction: row;
    align-items: center;
    gap: 0.5rem;
    list-style: none;
    margin: 0;
    padding: 0;
}

.navbar-collapse .btn-main {
    white-space: nowrap;
    position: relative;
    right: auto;
    margin-left: auto;
}

.nav-link {
    position: relative;
    padding: 0.5rem 1rem;
    font-size: 0.9rem;
    font-weight: 500;
    color: var(--text-secondary) !important;
    border-radius: var(--border-radius-sm);
    transition: var(--transition-base);
}

.nav-link:hover,
.nav-link.active {
    color: var(--primary) !important;
    background: rgba(59, 130, 246, 0.06);
}

/* Dropdown */
.dropdown {
    position: relative;
}

.dropdown-menu {
    position: absolute;
    top: 100%;
    left: 0;
    min-width: 200px;
    padding: 0.75rem;
    background: var(--bg-primary);
    border: 1px solid var(--glass-border);
    border-radius: var(--border-radius);
    box-shadow: var(--shadow-elevated);
    opacity: 0;
    visibility: hidden;
    transform: translateY(10px);
    transition: var(--transition-base);
    list-style: none;
}

.dropdown:hover .dropdown-menu {
    opacity: 1;
    visibility: visible;
    transform: translateY(5px);
}

.dropdown-menu li a {
    display: block;
    padding: 0.75rem 1rem;
    color: var(--text-secondary);
    font-size: 0.9rem;
    border-radius: var(--border-radius-sm);
    transition: var(--transition-base);
}

.dropdown-menu li a:hover {
    color: var(--primary);
    background: rgba(59, 130, 246, 0.06);
}

/* Mobile Menu Toggle */
.navbar-toggler {
    display: none;
    padding: 0.5rem;
    background: transparent;
    border: 1px solid var(--glass-border);
    border-radius: var(--border-radius-sm);
    cursor: pointer;
}

.navbar-toggler-icon {
    display: block;
    width: 22px;
    height: 2px;
    background: var(--text-primary);
    position: relative;
}

.navbar-toggler-icon::before,
.navbar-toggler-icon::after {
    content: '';
    position: absolute;
    width: 100%;
    height: 2px;
    background: var(--text-primary);
    left: 0;
}

.navbar-toggler-icon::before {
    top: -6px;
}

.navbar-toggler-icon::after {
    bottom: -6px;
}

/* ─────────────────────────────────────────────────────────────────────────────
   BUTTONS - Soft & Elegant
   ───────────────────────────────────────────────────────────────────────────── */
.btn-main {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    gap: 0.5rem;
    padding: 0.875rem 1.75rem;
    font-family: var(--font-body);
    font-size: 0.9rem;
    font-weight: 600;
    color: #ffffff !important;
    background: var(--gradient-primary);
    border: none;
    border-radius: var(--border-radius-full);
    cursor: pointer;
    transition: var(--transition-base);
    box-shadow: 0 4px 15px rgba(37, 99, 235, 0.4);
    position: relative;
    overflow: hidden;
    z-index: 1;
}

.btn-main::before {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background: linear-gradient(135deg, var(--secondary), var(--primary));
    /* Reversed gradient for hover */
    z-index: -1;
    transition: opacity 0.3s ease;
    opacity: 0;
}

.btn-main:hover {
    transform: translateY(-2px);
    box-shadow: 0 8px 25px rgba(59, 130, 246, 0.4);
}

.btn-main:hover::before {
    opacity: 1;
}

.btn-secondary-main {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    gap: 0.5rem;
    padding: 0.875rem 1.75rem;
    font-family: var(--font-body);
    font-size: 0.9rem;
    font-weight: 600;
    color: var(--primary-dark) !important;
    background: rgba(59, 130, 246, 0.16);
    border: 1px solid rgba(59, 130, 246, 0.1);
    border-radius: var(--border-radius-full);
    cursor: pointer;
    transition: var(--transition-base);
}

.btn-secondary-main:hover {
    background: rgba(59, 130, 246, 0.25);
    transform: translateY(-2px);
}

/* ─────────────────────────────────────────────────────────────────────────────
   HERO SECTION - Minimalist
   ───────────────────────────────────────────────────────────────────────────── */
.hero-slider {
    margin: 0;
}

/* ─────────────────────────────────────────────────────────────────────────────
   CHECKOUT & DASHBOARD - Aurora Digital
   ───────────────────────────────────────────────────────────────────────────── */

/* Checkout Steps */
.checkout-steps {
    display: flex;
    justify-content: center;
    align-items: center;
    gap: 1rem;
}

.step {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    opacity: 0.5;
}

.step.active {
    opacity: 1;
}

.step-icon {
    width: 35px;
    height: 35px;
    background: #fff;
    border: 2px solid var(--border-color);
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: 700;
    color: var(--text-muted);
    transition: var(--transition-base);
}

.step.active .step-icon {
    border-color: var(--primary);
    background: var(--bg-primary);
    color: var(--primary);
    box-shadow: 0 0 0 4px rgba(59, 130, 246, 0.1);
}

.step.completed .step-icon {
    background: var(--primary);
    border-color: var(--primary);
    color: #fff;
}

.step-label {
    font-weight: 600;
    text-transform: uppercase;
    font-size: 0.85rem;
    letter-spacing: 0.5px;
    color: var(--text-secondary);
}

.step-line {
    width: 50px;
    height: 2px;
    background: #e2e8f0;
}

.step-line.active {
    background: var(--primary);
}

/* Form Elements */
.form-label-ad {
    display: block;
    margin-bottom: 0.5rem;
    font-size: 0.875rem;
    font-weight: 600;
    color: var(--text-secondary);
}

.form-control-ad {
    width: 100%;
    background: #fff;
    border: 1px solid #e2e8f0;
    padding: 0.75rem 1rem;
    color: var(--text-primary);
    border-radius: 0.5rem;
    transition: var(--transition-base);
}

.form-control-ad:focus {
    outline: none;
    border-color: var(--primary);
    box-shadow: 0 0 0 4px rgba(59, 130, 246, 0.1);
}

.payment-methods {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 1rem;
}

.payment-radio {
    cursor: pointer;
}

.payment-radio input {
    display: none;
}

.radio-content {
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 0.75rem;
    padding: 1rem;
    border: 1px solid #e2e8f0;
    border-radius: 0.5rem;
    background: #fff;
    transition: var(--transition-base);
    color: var(--text-secondary);
    font-weight: 500;
}

.payment-radio input:checked+.radio-content {
    border-color: var(--primary);
    background: rgba(59, 130, 246, 0.05);
    color: var(--primary);
}

.plan-icon-small {
    width: 50px;
    height: 50px;
    background: linear-gradient(135deg, rgba(59, 130, 246, 0.1), rgba(236, 72, 153, 0.1));
    display: flex;
    align-items: center;
    justify-content: center;
    color: var(--primary);
    border-radius: 12px;
    font-size: 1.25rem;
}

.input-icon-wrapper {
    position: relative;
}

.input-icon {
    position: absolute;
    right: 1rem;
    top: 50%;
    transform: translateY(-50%);
    color: var(--text-muted);
}

/* Dashboard Sidebar */
.dashboard-wrapper {
    display: flex;
    min-height: 100vh;
    background: #f8fafc;
}

.dashboard-sidebar {
    width: 280px;
    background: #fff;
    padding: 2rem;
    display: flex;
    flex-direction: column;
    position: fixed;
    height: 100vh;
    overflow-y: auto;
    z-index: 10;
}

.dashboard-main {
    flex: 1;
    margin-left: 280px;
    padding: 3rem;
}

.sidebar-nav {
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
}

.nav-item {
    display: flex;
    align-items: center;
    gap: 1rem;
    padding: 0.875rem 1rem;
    color: var(--text-secondary);
    text-decoration: none;
    border-radius: 0.5rem;
    transition: var(--transition-base);
    font-weight: 500;
}

.nav-item:hover,
.nav-item.active {
    background: rgba(59, 130, 246, 0.08);
    color: var(--primary);
}

.nav-item i {
    width: 20px;
    text-align: center;
}

/* Dashboard Cards */
.dashboard-stat-card {
    transition: var(--transition-base);
}

.dashboard-stat-card:hover {
    transform: translateY(-5px);
    box-shadow: var(--shadow-card) !important;
}

.stat-icon {
    width: 48px;
    height: 48px;
    background: linear-gradient(135deg, var(--primary), var(--secondary));
    border-radius: 12px;
    display: flex;
    align-items: center;
    justify-content: center;
    color: #fff;
    font-size: 1.25rem;
    box-shadow: 0 4px 6px -1px rgba(0, 0, 0, 0.1);
}

.avatar-circle {
    width: 40px;
    height: 40px;
    background: linear-gradient(135deg, var(--secondary), var(--primary));
    color: #fff;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: 600;
    font-size: 0.9rem;
}

.btn-icon {
    width: 40px;
    height: 40px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    border: 1px solid #e2e8f0;
    color: var(--text-secondary);
    transition: var(--transition-base);
}

.btn-icon:hover {
    color: var(--primary);
    border-color: var(--primary);
}


.hero-overlay {
    position: absolute;
    inset: 0;
    /* Adjusted to match the specific "washed out" white look of the reference photo */
    background: linear-gradient(135deg,
            rgba(255, 255, 255, 0.75) 0%,
            rgba(255, 255, 255, 0.65) 50%,
            rgba(255, 255, 255, 0.75) 100%);
    z-index: 1;
}

.hero-slide {
    position: relative;
    display: flex;
    align-items: center;
    min-height: 100%;
}

.hero-slide::after {
    content: '';
    position: absolute;
    inset: 0;
    /* Subtle bottom gradient for depth */
    background: linear-gradient(0deg, rgba(15, 23, 42, 0.05) 0%, transparent 60%);
    z-index: 1;
    pointer-events: none;
}

.hero-content {
    position: relative;
    z-index: 2;
    max-width: 700px;
}

.hero h1 {
    color: var(--text-primary) !important;
}

.hero-description {
    color: var(--text-secondary) !important;
}

.hero-badge {
    display: inline-flex;
    align-items: center;
    gap: 0.5rem;
    padding: 0.5rem 1rem;
    margin-bottom: 1.5rem;
    font-size: 0.75rem;
    font-weight: 700;
    text-transform: uppercase;
    letter-spacing: 2px;
    color: var(--primary) !important;
    background: rgba(59, 130, 246, 0.08);
    border: 1px solid rgba(59, 130, 246, 0.1);
    border-radius: var(--border-radius-full);
}

.hero-badge span {
    color: var(--primary) !important;
}

.hero h1 {
    margin-bottom: 1.25rem;
    letter-spacing: -1px;
}

.hero h1 .highlight {
    position: relative;
    display: inline-block;
}

.hero h1 .highlight::after {
    content: '';
    position: absolute;
    bottom: 5px;
    left: 0;
    right: 0;
    height: 10px;
    background: linear-gradient(135deg, rgba(59, 130, 246, 0.1), rgba(236, 72, 153, 0.1));
    z-index: -1;
    border-radius: 2px;
}

.hero-description {
    font-size: 1.125rem;
    max-width: 500px;
    margin-bottom: 2rem;
}

.hero-buttons {
    display: flex;
    align-items: center;
    gap: 1rem;
    flex-wrap: wrap;
}

/* Swiper Navigation - Minimal */
.swiper-button-next,
.swiper-button-prev {
    color: var(--primary) !important;
    background: var(--bg-primary);
    width: 48px !important;
    height: 48px !important;
    border-radius: 50%;
    box-shadow: var(--shadow-card);
}

.swiper-button-next::after,
.swiper-button-prev::after {
    font-size: 0.875rem !important;
}

.swiper-button-next:hover,
.swiper-button-prev:hover {
    background: var(--primary);
    color: #ffffff !important;
}

.swiper-pagination-bullet {
    background: var(--text-muted) !important;
    opacity: 0.3;
}

.swiper-pagination-bullet-active {
    background: var(--primary) !important;
    opacity: 1;
}

/* ─────────────────────────────────────────────────────────────────────────────
   CLIENTS SECTION
   ───────────────────────────────────────────────────────────────────────────── */
.clients-section {
    padding: 3rem 0;
    background: var(--bg-secondary);
    border-top: 1px solid var(--glass-border);
    border-bottom: 1px solid var(--glass-border);
}

.clients-wrapper {
    display: flex;
    align-items: center;
    gap: 3rem;
}

.clients-label {
    /* Static List Added Below */
    white-space: nowrap;
    font-size: 0.85rem;
    font-weight: 500;
    color: var(--text-muted);
}

.clients-list {
    display: flex;
    align-items: center;
    justify-content: flex-start;
    gap: 3rem;
    flex: 1;
    overflow-x: auto;
    padding: 10px 0;
}

.clients-list::-webkit-scrollbar {
    display: none;
}

.client-logo {
    display: flex;
    align-items: center;
    justify-content: center;
    cursor: default;
    opacity: 0.5;
    transition: var(--transition-base);
}

.client-logo i {
    font-size: 2.2rem;
    color: var(--text-muted);
}

.client-logo:hover {
    opacity: 1;
}

.client-logo:hover i {
    color: var(--primary);
}

/* ─────────────────────────────────────────────────────────────────────────────
   FEATURE BOX - Clean Cards
   ───────────────────────────────────────────────────────────────────────────── */
.feature-box {
    position: relative;
    padding: 2rem;
    background: var(--bg-primary);
    border: 1px solid var(--glass-border);
    border-radius: var(--border-radius-lg);
    text-align: center;
    transition: var(--transition-base);
    height: 100%;
}

.feature-box:hover {
    transform: translateY(-10px);
    box-shadow: var(--shadow-elevated);
    border-color: rgba(59, 130, 246, 0.2);
}

.feature-box .icon {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: 64px;
    height: 64px;
    margin-bottom: 1.25rem;
    font-size: 1.5rem;
    background: linear-gradient(135deg, rgba(59, 130, 246, 0.1), rgba(236, 72, 153, 0.1));
    border-radius: var(--border-radius);
    color: var(--primary);
    transition: var(--transition-base);
}

.feature-box:hover .icon {
    background: var(--gradient-primary);
    color: #ffffff;
    transform: scale(1.1);
}

.feature-box h4 {
    margin-bottom: 0.75rem;
    color: var(--text-primary);
    font-size: 1.1rem;
}

.feature-box p {
    color: var(--text-secondary);
    margin-bottom: 0;
    font-size: 0.925rem;
}

/* ─────────────────────────────────────────────────────────────────────────────
   ABOUT SECTION
   ───────────────────────────────────────────────────────────────────────────── */
.about-image {
    position: relative;
    border-radius: var(--border-radius-lg);
    overflow: hidden;
    box-shadow: var(--shadow-elevated);
}

.about-image img {
    width: 100%;
    height: auto;
}

.experience-badge {
    position: absolute;
    bottom: 20px;
    right: -10px;
    padding: 1.25rem 1.5rem;
    background: var(--gradient-primary);
    border-radius: var(--border-radius);
    text-align: center;
    box-shadow: var(--shadow-elevated);
}

.experience-badge .number {
    display: block;
    font-family: var(--font-heading);
    font-size: 2rem;
    font-weight: 700;
    color: #ffffff;
    line-height: 1;
}

.experience-badge .text {
    font-size: 0.75rem;
    font-weight: 500;
    color: rgba(255, 255, 255, 0.9);
}

.about-content h2 {
    margin-bottom: 1.25rem;
}

.about-list {
    list-style: none;
    padding: 0;
    margin: 1.5rem 0;
}

.about-list li {
    display: flex;
    align-items: flex-start;
    gap: 0.75rem;
    margin-bottom: 1rem;
    color: var(--text-secondary);
}

.about-list li i {
    flex-shrink: 0;
    width: 20px;
    height: 20px;
    display: flex;
    align-items: center;
    justify-content: center;
    background: linear-gradient(135deg, rgba(59, 130, 246, 0.15), rgba(236, 72, 153, 0.15));
    border-radius: 50%;
    font-size: 0.6rem;
    color: var(--primary);
}

/* ─────────────────────────────────────────────────────────────────────────────
   COUNTER SECTION
   ───────────────────────────────────────────────────────────────────────────── */
.counter-section {
    padding: 4rem 0;
    background: var(--gradient-primary);
    border-radius: var(--border-radius-lg);
    margin: 0 1.5rem;
}

.counter-grid {
    display: grid;
    grid-template-columns: repeat(4, 1fr);
    gap: 2rem;
}

.counter-item {
    text-align: center;
    color: #ffffff;
}

.counter-item i {
    font-size: 2rem;
    margin-bottom: 0.75rem;
    opacity: 0.8;
}

.counter-number {
    display: block;
    font-family: var(--font-heading);
    font-size: 2.5rem;
    font-weight: 700;
    line-height: 1;
    margin-bottom: 0.25rem;
}

.counter-number::after {
    content: '+';
    color: rgba(255, 255, 255, 0.8);
    font-size: 1.5rem;
    vertical-align: top;
    margin-left: 5px;
}

.counter-label {
    font-size: 0.85rem;
    opacity: 0.9;
}

/* ─────────────────────────────────────────────────────────────────────────────
   SERVICES SECTION
   ───────────────────────────────────────────────────────────────────────────── */
.services-grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(300px, 1fr));
    gap: 1.5rem;
}

.service-card {
    position: relative;
    padding: 2rem;
    background: var(--bg-primary);
    border: 1px solid var(--glass-border);
    border-radius: var(--border-radius-lg);
    transition: var(--transition-base);
}

.service-card:hover {
    transform: translateY(-5px);
    box-shadow: var(--shadow-elevated);
    border-color: transparent;
}

.service-icon {
    width: 50px;
    height: 50px;
    display: flex;
    align-items: center;
    justify-content: center;
    margin-bottom: 1.25rem;
    font-size: 1.25rem;
    color: var(--primary);
    background: rgba(59, 130, 246, 0.08);
    border-radius: var(--border-radius);
    transition: var(--transition-base);
}

.service-card:hover .service-icon {
    background: var(--gradient-primary);
    color: #ffffff;
}

.service-card h4 {
    margin-bottom: 0.75rem;
    color: var(--text-primary);
    font-size: 1.1rem;
}

.service-card p {
    color: var(--text-secondary);
    margin-bottom: 1.25rem;
    font-size: 0.925rem;
}

.service-link {
    display: inline-flex;
    align-items: center;
    gap: 0.5rem;
    font-weight: 600;
    font-size: 0.875rem;
    color: var(--primary);
}

.service-link:hover {
    color: var(--secondary);
}

.service-link i {
    transition: var(--transition-base);
}

.service-link:hover i {
    transform: translateX(4px);
}

/* ─────────────────────────────────────────────────────────────────────────────
   PORTFOLIO SECTION
   ───────────────────────────────────────────────────────────────────────────── */
.portfolio-grid {
    display: grid;
    grid-template-columns: repeat(2, 1fr);
    gap: 1.5rem;
}

.portfolio-item {
    position: relative;
    border-radius: var(--border-radius-lg);
    overflow: hidden;
    cursor: pointer;
    box-shadow: var(--shadow-card);
}

.portfolio-image {
    width: 100%;
    height: 280px;
    object-fit: cover;
    transition: var(--transition-slow);
}

.portfolio-overlay {
    position: absolute;
    inset: 0;
    background: linear-gradient(to top, rgba(15, 23, 42, 0.9) 0%, transparent 60%);
    display: flex;
    flex-direction: column;
    justify-content: flex-end;
    padding: 1.5rem;
    opacity: 0;
    transition: var(--transition-base);
}

.portfolio-item:hover .portfolio-overlay {
    opacity: 1;
}

.portfolio-item:hover .portfolio-image {
    transform: scale(1.05);
}

.portfolio-category {
    display: inline-block;
    padding: 0.25rem 0.75rem;
    font-size: 0.7rem;
    font-weight: 600;
    text-transform: uppercase;
    letter-spacing: 1px;
    color: #ffffff;
    background: var(--gradient-primary);
    border-radius: var(--border-radius-full);
    margin-bottom: 0.5rem;
    width: fit-content;
}

.portfolio-overlay h4 {
    color: #ffffff;
    margin-bottom: 0;
    font-size: 1.125rem;
}

.portfolio-link {
    position: absolute;
    top: 1rem;
    right: 1rem;
    width: 44px;
    height: 44px;
    display: flex;
    align-items: center;
    justify-content: center;
    background: #ffffff;
    border-radius: 50%;
    color: var(--primary);
    transform: translateY(-20px);
    opacity: 0;
    transition: var(--transition-base);
}

.portfolio-item:hover .portfolio-link {
    transform: translateY(0);
    opacity: 1;
}

/* ─────────────────────────────────────────────────────────────────────────────
   TESTIMONIALS
   ───────────────────────────────────────────────────────────────────────────── */
.testimonials-section {
    background: var(--bg-secondary);
}

.testimonial-card {
    padding: 2rem;
    background: var(--bg-primary);
    border: 1px solid var(--glass-border);
    border-radius: var(--border-radius-lg);
    height: 100%;
    box-shadow: var(--shadow-sm);
}

.testimonial-rating {
    margin-bottom: 1rem;
}

.testimonial-rating i {
    color: #fbbf24;
    font-size: 0.875rem;
    margin-right: 0.15rem;
}

.testimonial-text {
    font-size: 1rem;
    font-style: italic;
    color: var(--text-secondary);
    margin-bottom: 1.5rem;
    line-height: 1.7;
}

.testimonial-author {
    display: flex;
    align-items: center;
    gap: 0.75rem;
}

.testimonial-author img {
    width: 50px;
    height: 50px;
    border-radius: 50%;
    object-fit: cover;
    border: 2px solid var(--bg-secondary);
}

.author-info h5 {
    color: var(--text-primary);
    margin-bottom: 0.15rem;
    font-size: 0.95rem;
}

.author-info span {
    font-size: 0.8rem;
    color: var(--primary);
}

/* ─────────────────────────────────────────────────────────────────────────────
   PRICING
   ───────────────────────────────────────────────────────────────────────────── */
.pricing-grid {
    display: grid;
    grid-template-columns: repeat(3, 1fr);
    gap: 1.5rem;
    align-items: start;
}

.pricing-card {
    position: relative;
    padding: 2rem;
    background: var(--bg-primary);
    border: 1px solid var(--glass-border);
    border-radius: var(--border-radius-lg);
    text-align: center;
    transition: var(--transition-base);
}

.pricing-card:hover {
    box-shadow: var(--shadow-elevated);
    border-color: transparent;
}

.pricing-card.featured {
    background: var(--gradient-primary);
    border: none;
    transform: scale(1.03);
}

.pricing-card.featured * {
    color: #ffffff;
}

.pricing-card.featured .btn-main {
    background: #ffffff;
    color: var(--primary) !important;
}

.pricing-badge {
    position: absolute;
    top: -10px;
    left: 50%;
    transform: translateX(-50%);
    padding: 0.4rem 1rem;
    font-size: 0.7rem;
    font-weight: 600;
    text-transform: uppercase;
    letter-spacing: 1px;
    color: #ffffff;
    background: var(--secondary);
    border-radius: var(--border-radius-full);
}

.pricing-header {
    margin-bottom: 1.5rem;
}

.pricing-header h4 {
    margin-bottom: 0.75rem;
    font-size: 1.1rem;
}

.price {
    display: flex;
    align-items: baseline;
    justify-content: center;
    gap: 0.15rem;
}

.price .currency {
    font-size: 1.25rem;
    font-weight: 600;
}

.price .amount {
    font-family: var(--font-heading);
    font-size: 3rem;
    font-weight: 700;
    line-height: 1;
}

.price .period {
    font-size: 0.9rem;
    color: var(--text-muted);
}

.pricing-card.featured .price .period {
    color: rgba(255, 255, 255, 0.8);
}

.pricing-features {
    list-style: none;
    padding: 0;
    margin: 0 0 1.5rem;
    text-align: left;
}

.pricing-features li {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    padding: 0.6rem 0;
    border-bottom: 1px solid var(--glass-border);
    font-size: 0.9rem;
}

.pricing-card.featured .pricing-features li {
    border-color: rgba(255, 255, 255, 0.15);
}

.pricing-features li i {
    font-size: 0.8rem;
}

.pricing-features li.disabled {
    opacity: 0.5;
}

/* ─────────────────────────────────────────────────────────────────────────────
   BLOG
   ───────────────────────────────────────────────────────────────────────────── */
.blog-grid {
    display: grid;
    grid-template-columns: repeat(3, 1fr);
    gap: 1.5rem;
}

.blog-card {
    background: var(--bg-primary);
    border: 1px solid var(--glass-border);
    border-radius: var(--border-radius-lg);
    overflow: hidden;
    transition: var(--transition-base);
}

.blog-card:hover {
    transform: translateY(-5px);
    box-shadow: var(--shadow-elevated);
    border-color: transparent;
}

.blog-image {
    position: relative;
    overflow: hidden;
}

.blog-image img {
    width: 100%;
    height: 180px;
    object-fit: cover;
    transition: var(--transition-slow);
}

.blog-card:hover .blog-image img {
    transform: scale(1.05);
}

.blog-category {
    position: absolute;
    top: 0.75rem;
    left: 0.75rem;
    padding: 0.25rem 0.75rem;
    font-size: 0.7rem;
    font-weight: 600;
    text-transform: uppercase;
    letter-spacing: 1px;
    color: #ffffff;
    background: var(--gradient-primary);
    border-radius: var(--border-radius-full);
}

.blog-content {
    padding: 1.25rem;
}

.blog-meta {
    display: flex;
    gap: 1rem;
    margin-bottom: 0.75rem;
    font-size: 0.8rem;
    color: var(--text-muted);
}

.blog-meta i {
    margin-right: 0.25rem;
    color: var(--primary);
}

.blog-content h4 {
    margin-bottom: 0.75rem;
    font-size: 1.05rem;
}

.blog-content h4 a {
    color: var(--text-primary);
}

.blog-content h4 a:hover {
    color: var(--primary);
}

.blog-content p {
    color: var(--text-secondary);
    margin-bottom: 0.75rem;
    display: -webkit-box;
    -webkit-line-clamp: 2;
    line-clamp: 2;
    -webkit-box-orient: vertical;
    overflow: hidden;
    font-size: 0.9rem;
}

.read-more {
    display: inline-flex;
    align-items: center;
    gap: 0.5rem;
    font-weight: 600;
    font-size: 0.85rem;
    color: var(--primary);
}

.read-more:hover {
    color: var(--secondary);
}

.read-more i {
    transition: var(--transition-base);
}

.read-more:hover i {
    transform: translateX(4px);
}

/* ─────────────────────────────────────────────────────────────────────────────
   CTA SECTION
   ───────────────────────────────────────────────────────────────────────────── */
.cta-section {
    padding: 5rem 0;
    background: var(--gradient-primary);
    text-align: center;
    border-radius: var(--border-radius-lg);
    margin: 0 1.5rem 3rem;
}

.cta-content h2 {
    color: #ffffff;
    margin-bottom: 0.75rem;
    font-size: 2rem;
}

.cta-content p {
    color: rgba(255, 255, 255, 0.9);
    max-width: 500px;
    margin: 0 auto 1.5rem;
}

.cta-buttons {
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 1rem;
    flex-wrap: wrap;
}

.cta-buttons .btn-main {
    background: #ffffff;
    color: var(--primary) !important;
    box-shadow: var(--shadow-card);
}

.cta-buttons .btn-secondary-main {
    background: rgba(255, 255, 255, 0.15);
    color: #ffffff !important;
}

.cta-buttons .btn-secondary-main:hover {
    background: rgba(255, 255, 255, 0.25);
}

/* ─────────────────────────────────────────────────────────────────────────────
   FOOTER
   ───────────────────────────────────────────────────────────────────────────── */
.footer {
    background: var(--bg-secondary);
    padding: 4rem 0 1.5rem;
    border-top: 1px solid var(--glass-border);
}

.footer-grid {
    display: grid;
    grid-template-columns: 2fr 1fr 1fr 1fr;
    gap: 2.5rem;
    margin-bottom: 2.5rem;
}

.footer-brand {
    font-family: var(--font-heading);
    font-size: 1.5rem;
    font-weight: 800;
    color: var(--text-primary);
    margin-bottom: 0.75rem;
}

.footer-brand span {
    background: var(--gradient-primary);
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    background-clip: text;
}

.footer-description {
    color: var(--text-secondary);
    margin-bottom: 1.25rem;
    font-size: 0.925rem;
}

.footer-social {
    display: flex;
    gap: 0.5rem;
}

.social-link {
    width: 38px;
    height: 38px;
    display: flex;
    align-items: center;
    justify-content: center;
    background: var(--bg-primary);
    border: 1px solid var(--glass-border);
    border-radius: 50%;
    color: var(--text-secondary);
    transition: var(--transition-base);
}

.social-link:hover {
    background: var(--gradient-primary);
    border-color: transparent;
    color: #ffffff;
    transform: translateY(-2px);
}

.footer-title {
    font-size: 0.95rem;
    font-weight: 600;
    color: var(--text-primary);
    margin-bottom: 1.25rem;
}

.footer-links {
    list-style: none;
    padding: 0;
    margin: 0;
}

.footer-links li {
    margin-bottom: 0.6rem;
}

.footer-links a {
    color: var(--text-secondary);
    font-size: 0.9rem;
    transition: var(--transition-base);
}

.footer-links a:hover {
    color: var(--primary);
}

.footer-contact li {
    display: flex;
    align-items: flex-start;
    gap: 0.75rem;
    margin-bottom: 0.75rem;
    color: var(--text-secondary);
    font-size: 0.9rem;
}

.footer-contact i {
    color: var(--primary);
    margin-top: 0.2rem;
    font-size: 0.875rem;
}

.footer-bottom {
    padding-top: 1.5rem;
    border-top: 1px solid var(--glass-border);
    display: flex;
    justify-content: space-between;
    align-items: center;
}

.footer-bottom p {
    color: var(--text-muted);
    margin: 0;
    font-size: 0.875rem;
}

.footer-bottom-links {
    display: flex;
    gap: 1.5rem;
}

.footer-bottom-links a {
    color: var(--text-muted);
    font-size: 0.875rem;
}

.footer-bottom-links a:hover {
    color: var(--primary);
}

/* ─────────────────────────────────────────────────────────────────────────────
   PAGE HEADER
   ───────────────────────────────────────────────────────────────────────────── */
.page-header {
    padding: 9rem 0 3rem;
    background: var(--bg-secondary);
    text-align: center;
    position: relative;
}

.page-header::before {
    content: '';
    position: absolute;
    top: 0;
    left: 50%;
    transform: translateX(-50%);
    width: 100%;
    height: 100%;
    background: var(--gradient-radial);
}

.page-header-content {
    position: relative;
    z-index: 1;
}

.page-header h1 {
    margin-bottom: 0.75rem;
}

.page-header p {
    color: var(--text-secondary);
    max-width: 500px;
    margin: 0 auto;
}

.breadcrumb {
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 0.5rem;
    margin-top: 1.25rem;
    font-size: 0.85rem;
}

.breadcrumb a {
    color: var(--text-muted);
}

.breadcrumb a:hover {
    color: var(--primary);
}

.breadcrumb span {
    color: var(--text-muted);
}

.breadcrumb .current {
    color: var(--primary);
}

/* ─────────────────────────────────────────────────────────────────────────────
   BACK TO TOP
   ───────────────────────────────────────────────────────────────────────────── */
.back-to-top {
    position: fixed;
    bottom: 1.5rem;
    right: 1.5rem;
    width: 46px;
    height: 46px;
    display: flex;
    align-items: center;
    justify-content: center;
    background: var(--gradient-primary);
    border: none;
    border-radius: 50%;
    color: #ffffff;
    font-size: 1.1rem;
    cursor: pointer;
    opacity: 0;
    visibility: hidden;
    transform: translateY(20px);
    transition: var(--transition-base);
    z-index: 999;
    box-shadow: 0 4px 15px rgba(59, 130, 246, 0.3);
}

.back-to-top.show {
    opacity: 1;
    visibility: visible;
    transform: translateY(0);
}

.back-to-top:hover {
    transform: translateY(-3px);
    box-shadow: 0 8px 25px rgba(59, 130, 246, 0.4);
}

/* ─────────────────────────────────────────────────────────────────────────────
   FAQ
   ───────────────────────────────────────────────────────────────────────────── */
.faq-item {
    margin-bottom: 0.75rem;
    background: var(--bg-primary);
    border: 1px solid var(--glass-border);
    border-radius: var(--border-radius);
    overflow: hidden;
}

.faq-question {
    width: 100%;
    padding: 1.25rem;
    display: flex;
    justify-content: space-between;
    align-items: center;
    background: transparent;
    border: none;
    font-size: 0.95rem;
    font-weight: 600;
    color: var(--text-primary);
    cursor: pointer;
    transition: var(--transition-base);
    text-align: left;
}

.faq-question:hover {
    background: var(--bg-secondary);
}

.faq-question i {
    transition: var(--transition-base);
    color: var(--primary);
}

.faq-item.active .faq-question i {
    transform: rotate(180deg);
}

.faq-answer {
    max-height: 0;
    overflow: hidden;
    transition: max-height var(--transition-base);
}

.faq-item.active .faq-answer {
    max-height: 500px;
}

.faq-answer p {
    padding: 0 1.25rem 1.25rem;
    color: var(--text-secondary);
    margin: 0;
    font-size: 0.925rem;
}

/* ─────────────────────────────────────────────────────────────────────────────
   CONTACT FORM
   ───────────────────────────────────────────────────────────────────────────── */
.contact-form {
    padding: 2.5rem;
    background: var(--bg-primary);
    border: 1px solid var(--glass-border);
    border-radius: var(--border-radius-lg);
    box-shadow: var(--shadow-card);
}

.form-group {
    margin-bottom: 1.25rem;
}

.form-group label {
    display: block;
    margin-bottom: 0.4rem;
    font-weight: 500;
    color: var(--text-primary);
    font-size: 0.9rem;
}

.form-control {
    width: 100%;
    padding: 0.875rem 1rem;
    font-family: var(--font-body);
    font-size: 0.95rem;
    color: var(--text-primary);
    background: var(--bg-secondary);
    border: 1px solid var(--glass-border);
    border-radius: var(--border-radius-sm);
    transition: var(--transition-base);
}

.form-control:focus {
    outline: none;
    border-color: var(--primary);
    box-shadow: 0 0 0 3px rgba(59, 130, 246, 0.1);
}

.form-control::placeholder {
    color: var(--text-muted);
}

textarea.form-control {
    min-height: 130px;
    resize: vertical;
}

/* ─────────────────────────────────────────────────────────────────────────────
   TEAM
   ───────────────────────────────────────────────────────────────────────────── */
.team-grid {
    display: grid;
    grid-template-columns: repeat(4, 1fr);
    gap: 1.5rem;
}

.team-card {
    background: var(--bg-primary);
    border: 1px solid var(--glass-border);
    border-radius: var(--border-radius-lg);
    overflow: hidden;
    text-align: center;
    transition: var(--transition-base);
}

.team-card:hover {
    transform: translateY(-8px);
    box-shadow: var(--shadow-elevated);
    border-color: transparent;
}

.team-image {
    position: relative;
    overflow: hidden;
}

.team-image img {
    width: 100%;
    height: 260px;
    object-fit: cover;
    transition: var(--transition-slow);
}

.team-card:hover .team-image img {
    transform: scale(1.05);
}

.team-social {
    position: absolute;
    bottom: 0;
    left: 0;
    right: 0;
    padding: 0.75rem;
    background: linear-gradient(to top, rgba(15, 23, 42, 0.85), transparent);
    display: flex;
    justify-content: center;
    gap: 0.4rem;
    transform: translateY(100%);
    transition: var(--transition-base);
}

.team-card:hover .team-social {
    transform: translateY(0);
}

.team-social a {
    width: 34px;
    height: 34px;
    display: flex;
    align-items: center;
    justify-content: center;
    background: rgba(255, 255, 255, 0.9);
    border-radius: 50%;
    color: var(--primary);
    transition: var(--transition-base);
}

.team-social a:hover {
    background: var(--gradient-primary);
    color: #ffffff;
}

.team-info {
    padding: 1.25rem;
}

.team-info h4 {
    margin-bottom: 0.2rem;
    font-size: 1rem;
}

.team-info span {
    font-size: 0.85rem;
    color: var(--primary);
}

/* ─────────────────────────────────────────────────────────────────────────────
   MAP
   ───────────────────────────────────────────────────────────────────────────── */
.map-container {
    border-radius: var(--border-radius-lg);
    overflow: hidden;
    height: 350px;
    box-shadow: var(--shadow-card);
}

.map-container iframe {
    width: 100%;
    height: 100%;
    border: 0;
}

/* ─────────────────────────────────────────────────────────────────────────────
   ANIMATIONS
   ───────────────────────────────────────────────────────────────────────────── */
.fade-in-up {
    animation: fadeInUp 0.7s ease-out forwards;
}

@keyframes fadeInUp {
    from {
        opacity: 0;
        transform: translateY(25px);
    }

    to {
        opacity: 1;
        transform: translateY(0);
    }
}

/* ─────────────────────────────────────────────────────────────────────────────
   RESPONSIVE
   ───────────────────────────────────────────────────────────────────────────── */
@media (max-width: 1200px) {
    .pricing-grid {
        grid-template-columns: repeat(2, 1fr);
    }

    .pricing-card.featured {
        transform: none;
    }

    .footer-grid {
        grid-template-columns: repeat(2, 1fr);
    }
}

@media (max-width: 992px) {
    :root {
        --section-padding: 70px;
    }

    .top-bar {
        display: none;
    }

    .navbar-toggler {
        display: block;
    }

    .navbar-collapse {
        position: fixed;
        top: 65px;
        left: 0;
        right: 0;
        background: var(--bg-primary);
        flex-direction: column;
        padding: 1.5rem;
        border-bottom: 1px solid var(--glass-border);
        box-shadow: var(--shadow-elevated);
        display: none !important;
    }

    .navbar-collapse.show {
        display: flex !important;
    }

    .nav-menu {
        flex-direction: column;
        width: 100%;
    }

    .nav-link {
        width: 100%;
        padding: 0.875rem;
    }

    .navbar-collapse .btn-main {
        position: relative;
        margin-top: 1rem;
    }

    .dropdown-menu {
        position: static;
        opacity: 1;
        visibility: visible;
        transform: none;
        box-shadow: none;
        background: var(--bg-secondary);
        margin-top: 0.5rem;
    }

    .counter-section {
        margin: 0;
        border-radius: 0;
    }

    .cta-section {
        margin: 0;
        border-radius: 0;
    }

    .counter-grid {
        grid-template-columns: repeat(2, 1fr);
    }

    .portfolio-grid {
        grid-template-columns: 1fr;
    }

    .blog-grid {
        grid-template-columns: repeat(2, 1fr);
    }

    .team-grid {
        grid-template-columns: repeat(2, 1fr);
    }
}

@media (max-width: 768px) {
    :root {
        --section-padding: 50px;
    }

    .pricing-grid {
        grid-template-columns: 1fr;
    }

    .footer-grid {
        grid-template-columns: 1fr;
        text-align: center;
    }

    .footer-social {
        justify-content: center;
    }

    .footer-bottom {
        flex-direction: column;
        gap: 0.75rem;
        text-align: center;
    }

    .blog-grid {
        grid-template-columns: 1fr;
    }

    .clients-wrapper {
        flex-direction: column;
    }

    .experience-badge {
        right: 0;
        bottom: 15px;
    }
}

@media (max-width: 576px) {
    .hero-buttons {
        flex-direction: column;
        width: 100%;
    }

    .hero-buttons .btn-main,
    .hero-buttons .btn-secondary-main {
        width: 100%;
    }

    .cta-buttons {
        flex-direction: column;
        width: 100%;
    }

    .cta-buttons .btn-main,
    .cta-buttons .btn-secondary-main {
        width: 100%;
    }

    .counter-grid {
        grid-template-columns: 1fr;
    }

    .team-grid {
        grid-template-columns: 1fr;
    }
}

/* ─────────────────────────────────────────────────────────────────────────────
   AURORA DIGITAL UNIQUE COMPONENTS
   ───────────────────────────────────────────────────────────────────────────── */

/* Clean Vertical Timeline */
.timeline-vertical-aurora {
    position: relative;
    max-width: 800px;
    margin: 4rem auto;
    padding: 2rem 0;
}

.timeline-vertical-aurora::before {
    content: '';
    position: absolute;
    top: 0;
    left: 20px;
    height: 100%;
    width: 2px;
    background: var(--glass-border);
}

.timeline-item-aurora {
    position: relative;
    padding-left: 60px;
    margin-bottom: 3rem;
}

.timeline-marker {
    position: absolute;
    left: 11px;
    top: 5px;
    width: 20px;
    height: 20px;
    background: var(--bg-primary);
    border: 3px solid var(--primary);
    border-radius: 50%;
}

.timeline-content-aurora {
    padding: 1.5rem;
    background: var(--bg-secondary);
    border-radius: var(--border-radius);
    transition: var(--transition-base);
}

.timeline-item-aurora:hover .timeline-content-aurora {
    transform: translateX(10px);
    background: #ffffff;
    box-shadow: var(--shadow-card);
}

.timeline-content-aurora .year {
    font-weight: 800;
    color: var(--primary);
    font-size: 0.85rem;
    display: block;
    margin-bottom: 0.5rem;
}

/* Value Cards with Gradient Border */
.value-card-aurora {
    padding: 2.5rem;
    background: #ffffff;
    border-radius: var(--border-radius-lg);
    box-shadow: var(--shadow-card);
    transition: var(--transition-base);
    height: 100%;
    border-bottom: 4px solid transparent;
}

.value-card-aurora:hover {
    transform: translateY(-8px);
    border-bottom-color: var(--primary);
}

/* Service Cards (Aurora) */
.service-card-aurora {
    background: #ffffff;
    border-radius: var(--border-radius-lg);
    padding: 3rem;
    box-shadow: var(--shadow-card);
    transition: var(--transition-base);
    height: 100%;
    border: 1px solid var(--border-color);
    position: relative;
    overflow: hidden;
}

.service-card-aurora:hover {
    transform: translateY(-5px);
    box-shadow: var(--shadow-elevated);
    border-color: var(--primary);
}

.service-header {
    display: flex;
    align-items: center;
    gap: 1.5rem;
    margin-bottom: 1.5rem;
}

.service-icon-aurora {
    width: 60px;
    height: 60px;
    background: var(--bg-secondary);
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 1.5rem;
    color: var(--primary);
    transition: var(--transition-base);
}

.service-card-aurora:hover .service-icon-aurora {
    background: var(--primary);
    color: #ffffff;
}

.service-list-aurora {
    list-style: none;
    padding: 0;
    margin: 2rem 0;
}

.service-list-aurora li {
    margin-bottom: 0.75rem;
    color: var(--text-muted);
    display: flex;
    align-items: center;
    gap: 0.75rem;
}

.service-list-aurora li i {
    color: var(--primary);
    font-size: 0.9rem;
}

.service-meta {
    display: flex;
    gap: 0.5rem;
    margin-bottom: 2rem;
    flex-wrap: wrap;
}

.badge-aurora {
    background: var(--bg-secondary);
    color: var(--primary);
    padding: 0.25rem 0.75rem;
    border-radius: 50px;
    font-size: 0.75rem;
    font-weight: 600;
}

.service-link-aurora {
    color: var(--primary);
    font-weight: 600;
    display: inline-flex;
    align-items: center;
    gap: 0.5rem;
    transition: var(--transition-base);
}

.service-link-aurora:hover {
    gap: 0.75rem;
}

/* Process Flow (Aurora) */
.process-flow-aurora {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 2rem 0;
}

.process-step-aurora {
    text-align: center;
    width: 200px;
    position: relative;
}

.step-number {
    width: 50px;
    height: 50px;
    background: var(--bg-primary);
    border: 2px solid var(--primary);
    color: var(--primary);
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: 700;
    margin: 0 auto 1.5rem;
    z-index: 2;
    position: relative;
}

.process-connector {
    flex: 1;
    height: 2px;
    background: var(--border-color);
    margin: 0 1rem;
    margin-bottom: 2rem;
    /* Align with dots */
    position: relative;
}

.value-icon {
    width: 60px;
    height: 60px;
    background: rgba(59, 130, 246, 0.1);
    border-radius: 12px;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 1.5rem;
    color: var(--primary);
    margin-bottom: 1.5rem;
}

/* Compliance Grid */
.compliance-grid-aurora {
    display: flex;
    flex-wrap: wrap;
    justify-content: center;
    gap: 3rem;
    padding: 3rem;
    background: var(--bg-secondary);
    border-radius: var(--border-radius-lg);
}

.compliance-item {
    text-align: center;
    max-width: 150px;
}

.compliance-item i {
    font-size: 2.5rem;
    color: var(--text-muted);
    margin-bottom: 1rem;
    display: block;
}

/* Impact Case Studies */
.case-study-aurora {
    background: #ffffff;
    border-radius: var(--border-radius-lg);
    overflow: hidden;
    box-shadow: var(--shadow-card);
    margin-bottom: 4rem;
}

.case-image {
    background-size: cover;
    background-position: center;
    height: 100%;
    min-height: 400px;
    position: relative;
    padding: 2rem;
}

.case-category {
    background: #ffffff;
    padding: 0.5rem 1rem;
    border-radius: 50px;
    font-weight: 700;
    font-size: 0.75rem;
    text-transform: uppercase;
    color: var(--primary);
}

.case-content {
    padding: 4rem;
}

.case-metrics {
    display: flex;
    gap: 2rem;
    margin: 2rem 0;
}

.metric-value {
    display: block;
    font-size: 2rem;
    font-weight: 800;
    color: var(--primary);
}

.metric-label {
    font-size: 0.85rem;
    color: var(--text-muted);
}

/* ─────────────────────────────────────────────────────────────────────────────
   BLOG (AURORA UNIQUE)
   ───────────────────────────────────────────────────────────────────────────── */
.blog-card-aurora {
    background: #ffffff;
    border-radius: var(--border-radius-lg);
    overflow: hidden;
    box-shadow: var(--shadow-card);
    margin-bottom: 2rem;
    transition: var(--transition-base);
    border: 1px solid var(--glass-border);
}

.blog-card-aurora:hover {
    transform: translateY(-5px);
    box-shadow: var(--shadow-elevated);
    border-color: rgba(59, 130, 246, 0.2);
}

.blog-image-aurora {
    position: relative;
    overflow: hidden;
}

.blog-image-aurora img {
    width: 100%;
    height: auto;
    transition: var(--transition-slow);
}

.blog-card-aurora:hover .blog-image-aurora img {
    transform: scale(1.05);
}

.blog-category-aurora {
    position: absolute;
    top: 20px;
    left: 20px;
    background: var(--gradient-primary);
    color: #ffffff;
    padding: 0.4rem 1rem;
    border-radius: 50px;
    font-size: 0.75rem;
    font-weight: 600;
}

.blog-content-aurora {
    padding: 2rem;
}

.blog-meta-aurora {
    display: flex;
    gap: 1.5rem;
    margin-bottom: 1rem;
    font-size: 0.85rem;
    color: var(--text-muted);
}

.blog-meta-aurora i {
    color: var(--primary);
    margin-right: 0.3rem;
}

.blog-card-aurora h2 a,
.blog-card-aurora h3 a {
    color: var(--text-primary);
    text-decoration: none;
    transition: var(--transition-base);
}

.blog-card-aurora h2 a:hover,
.blog-card-aurora h3 a:hover {
    color: var(--primary);
}

.read-more-aurora {
    display: inline-flex;
    align-items: center;
    gap: 0.5rem;
    margin-top: 1rem;
    font-weight: 600;
    color: var(--primary);
    transition: var(--transition-base);
}

.read-more-aurora:hover {
    gap: 0.75rem;
}

/* Small Blog Card Style */
.blog-thumb-aurora {
    height: 100%;
    overflow: hidden;
}

.blog-thumb-aurora img {
    width: 100%;
    height: 100%;
    object-fit: cover;
    transition: var(--transition-slow);
}

.blog-card-aurora:hover .blog-thumb-aurora img {
    transform: scale(1.05);
}

.blog-category-aurora-small {
    display: inline-block;
    font-size: 0.75rem;
    font-weight: 600;
    color: var(--primary);
    background: rgba(59, 130, 246, 0.1);
    padding: 0.2rem 0.6rem;
    border-radius: 4px;
    margin-bottom: 0.75rem;
}

/* Sidebar */
.blog-sidebar-aurora .sidebar-widget {
    background: #ffffff;
    padding: 2rem;
    border-radius: var(--border-radius-lg);
    box-shadow: var(--shadow-card);
    margin-bottom: 2rem;
    border: 1px solid var(--glass-border);
}

.sidebar-widget h4 {
    margin-bottom: 1.5rem;
    font-size: 1.25rem;
}

.search-form-aurora {
    display: flex;
    gap: 0.5rem;
}

.search-form-aurora input {
    flex: 1;
    padding: 0.75rem;
    border: 1px solid var(--glass-border);
    border-radius: var(--border-radius-sm);
    background: var(--bg-secondary);
}

.search-form-aurora button {
    background: var(--primary);
    color: #ffffff;
    border: none;
    width: 45px;
    border-radius: var(--border-radius-sm);
    cursor: pointer;
}

.category-list-aurora {
    list-style: none;
    padding: 0;
    margin: 0;
}

.category-list-aurora li {
    margin-bottom: 0.75rem;
}

.category-list-aurora a {
    display: flex;
    justify-content: space-between;
    padding: 0.75rem;
    background: var(--bg-secondary);
    border-radius: var(--border-radius-sm);
    color: var(--text-secondary);
    transition: var(--transition-base);
}

.category-list-aurora a:hover {
    background: var(--primary);
    color: #ffffff;
}

.category-list-aurora a span {
    background: rgba(0, 0, 0, 0.08);
    border-radius: 50px;
    font-size: 0.75rem;
    font-weight: 600;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    min-width: 24px;
    height: 24px;
    line-height: 1;
    padding: 0 6px;
    color: var(--text-secondary);
}

.popular-posts-aurora {
    list-style: none;
    padding: 0;
    margin: 0;
}

.popular-posts-aurora li {
    margin-bottom: 1rem;
    padding-bottom: 1rem;
    border-bottom: 1px solid var(--glass-border);
}

.popular-posts-aurora li:last-child {
    border-bottom: none;
    padding-bottom: 0;
    margin-bottom: 0;
}

.popular-posts-aurora a {
    display: block;
}

.popular-posts-aurora .post-title {
    display: block;
    font-weight: 600;
    color: var(--text-primary);
    margin-bottom: 0.25rem;
    line-height: 1.4;
}

.popular-posts-aurora .post-date {
    font-size: 0.8rem;
    color: var(--text-muted);
}

.popular-posts-aurora a:hover .post-title {
    color: var(--primary);
}

/* Pagination (Aurora) */
.pagination-aurora {
    margin-top: 3rem;
}

.pagination-aurora .pagination {
    justify-content: center;
    gap: 0.5rem;
}

.pagination-aurora .page-link {
    width: 40px;
    height: 40px;
    display: flex;
    align-items: center;
    justify-content: center;
    border: none;
    border-radius: 50%;
    color: var(--text-secondary);
    font-weight: 600;
}

.pagination-aurora .page-item.active .page-link {
    background: var(--gradient-primary);
    color: #ffffff;
    box-shadow: var(--shadow-glow);
}

.pagination-aurora .page-link:hover {
    background: var(--bg-secondary);
    color: var(--primary);
}

/* Contact Form Aurora (Enhanced) */
.contact-form-aurora {
    background: #ffffff;
    padding: 3rem;
    border-radius: var(--border-radius-lg);
    box-shadow: var(--shadow-card);
    border: 1px solid var(--glass-border);
}

.contact-form-aurora h3 {
    margin-bottom: 1rem;
    color: var(--text-primary);
}

.form-group-aurora {
    margin-bottom: 1.5rem;
}

.form-group-aurora label {
    display: block;
    margin-bottom: 0.5rem;
    font-weight: 600;
    color: var(--text-primary);
    font-size: 0.9rem;
}

.form-group-aurora .form-control {
    padding: 0.875rem 1rem;
    border: 1px solid var(--glass-border);
    border-radius: var(--border-radius-sm);
