/* ═══════════════════════════════════════════════════════════════════════════════
   ABOUT PAGE - PREMIUM STYLES
   Enhanced visual design for the About Us page
   ═══════════════════════════════════════════════════════════════════════════════ */

/* Page Header Aurora - Premium Enhancement */
.page-header-aurora {
    padding: 180px 0 100px;
    background: linear-gradient(135deg, rgba(59, 130, 246, 0.03) 0%, rgba(236, 72, 153, 0.05) 50%, rgba(139, 92, 246, 0.03) 100%);
    position: relative;
    overflow: hidden;
}

.page-header-aurora::before {
    content: '';
    position: absolute;
    top: -50%;
    left: -50%;
    width: 200%;
    height: 200%;
    background: radial-gradient(circle at 30% 30%, rgba(59, 130, 246, 0.08) 0%, transparent 40%),
        radial-gradient(circle at 70% 70%, rgba(236, 72, 153, 0.08) 0%, transparent 40%);
    animation: aurora-float 20s ease-in-out infinite;
    pointer-events: none;
}

@keyframes aurora-float {

    0%,
    100% {
        transform: translate(0, 0) rotate(0deg);
    }

    33% {
        transform: translate(2%, 2%) rotate(1deg);
    }

    66% {
        transform: translate(-2%, 1%) rotate(-1deg);
    }
}

.page-header-aurora .subtitle {
    display: inline-flex;
    align-items: center;
    gap: 0.5rem;
    padding: 0.6rem 1.25rem;
    font-size: 0.75rem;
    font-weight: 700;
    text-transform: uppercase;
    letter-spacing: 3px;
    color: var(--primary);
    background: linear-gradient(135deg, rgba(59, 130, 246, 0.1), rgba(236, 72, 153, 0.1));
    backdrop-filter: blur(10px);
    border-radius: var(--border-radius-full);
    margin-bottom: 1.5rem;
    border: 1px solid rgba(59, 130, 246, 0.15);
}

.page-header-aurora h1 {
    font-size: clamp(2.5rem, 5vw, 4rem);
    font-weight: 800;
    line-height: 1.15;
    letter-spacing: -1.5px;
    margin-bottom: 1.5rem;
    background: var(--bg-secondary);
    position: relative;
    z-index: 1;
}

.page-header-aurora .lead {
    font-size: 1.25rem;
    color: var(--text-secondary);
    max-width: 600px;
    margin: 0 auto;
    line-height: 1.8;
    opacity: 0.9;
}

/* Story Section - Enhanced */
.story-content-aurora {
    position: relative;
    z-index: 1;
}

.story-content-aurora .subtitle {
    display: inline-flex;
    align-items: center;
    gap: 0.5rem;
    padding: 0.5rem 1rem;
    font-size: 0.75rem;
    font-weight: 700;
    text-transform: uppercase;
    letter-spacing: 2px;
    color: var(--primary);
    background: rgba(59, 130, 246, 0.08);
    border-radius: var(--border-radius-full);
    margin-bottom: 1rem;
}

.story-content-aurora h2 {
    font-size: clamp(1.75rem, 3vw, 2.5rem);
    font-weight: 800;
    margin-bottom: 2rem;
}

.story-content-aurora .lead {
    font-size: 1.25rem;
    color: var(--text-primary);
    font-weight: 500;
    line-height: 1.7;
    margin-bottom: 1.5rem;
}

.story-content-aurora p {
    font-size: 1.05rem;
    line-height: 1.85;
    color: var(--text-secondary);
}

/* Image Grid for About Page */
.section-padding .col-md-4 img {
    border-radius: 20px;
    box-shadow: 0 20px 50px -15px rgba(0, 0, 0, 0.15);
    transition: all 0.5s cubic-bezier(0.23, 1, 0.32, 1);
    border: 3px solid rgba(255, 255, 255, 0.8);
}

.section-padding .col-md-4 img:hover {
    transform: translateY(-12px) scale(1.02);
    box-shadow: 0 30px 60px -15px rgba(59, 130, 246, 0.25);
    border-color: rgba(59, 130, 246, 0.2);
}

/* Values Grid - Premium Design */
.values-grid-aurora {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(280px, 1fr));
    gap: 2rem;
    margin-top: 3rem;
}

.value-card-aurora {
    position: relative;
    padding: 2.5rem;
    background: rgba(255, 255, 255, 0.95);
    backdrop-filter: blur(20px);
    border-radius: 24px;
    box-shadow: 0 10px 40px -10px rgba(0, 0, 0, 0.08);
    transition: all 0.5s cubic-bezier(0.23, 1, 0.32, 1);
    height: 100%;
    border: 1px solid rgba(255, 255, 255, 0.9);
    overflow: hidden;
}

.value-card-aurora::before {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    height: 4px;
    background: var(--gradient-primary);
    opacity: 0;
    transition: opacity 0.4s ease;
}

.value-card-aurora::after {
    content: '';
    position: absolute;
    bottom: -50%;
    right: -50%;
    width: 100%;
    height: 100%;
    background: radial-gradient(circle, rgba(59, 130, 246, 0.06) 0%, transparent 60%);
    opacity: 0;
    transition: opacity 0.5s ease;
    pointer-events: none;
}

.value-card-aurora:hover {
    transform: translateY(-12px);
    box-shadow: 0 25px 60px -15px rgba(59, 130, 246, 0.2);
    border-color: rgba(59, 130, 246, 0.15);
}

.value-card-aurora:hover::before {
    opacity: 1;
}

.value-card-aurora:hover::after {
    opacity: 1;
}

.value-card-aurora .value-icon {
    width: 70px;
    height: 70px;
    background: linear-gradient(135deg, rgba(59, 130, 246, 0.12) 0%, rgba(236, 72, 153, 0.12) 100%);
    border-radius: 18px;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 1.75rem;
    color: var(--primary);
    margin-bottom: 1.75rem;
    transition: all 0.5s cubic-bezier(0.23, 1, 0.32, 1);
    position: relative;
    z-index: 1;
}

.value-card-aurora:hover .value-icon {
    background: var(--gradient-primary);
    color: #ffffff;
    transform: scale(1.1) rotate(-5deg);
    box-shadow: 0 15px 30px -10px rgba(59, 130, 246, 0.4);
}

.value-card-aurora h4 {
    font-size: 1.25rem;
    font-weight: 700;
    color: var(--text-primary);
    margin-bottom: 1rem;
    position: relative;
    z-index: 1;
}

.value-card-aurora p {
    font-size: 0.95rem;
    line-height: 1.75;
    color: var(--text-secondary);
    margin-bottom: 0;
    position: relative;
    z-index: 1;
}

/* Timeline - Enhanced Vertical Design */
.timeline-vertical-aurora {
    position: relative;
    max-width: 850px;
    margin: 4rem auto;
    padding: 2rem 0;
}

.timeline-vertical-aurora::before {
    content: '';
    position: absolute;
    top: 0;
    left: 22px;
    height: 100%;
    width: 3px;
    background: linear-gradient(180deg, var(--primary) 0%, var(--secondary) 100%);
    border-radius: 10px;
    opacity: 0.2;
}

.timeline-item-aurora {
    position: relative;
    padding-left: 70px;
    margin-bottom: 2.5rem;
    opacity: 1;
    transform: translateX(0);
    transition: all 0.5s ease;
}

.timeline-item-aurora:last-child {
    margin-bottom: 0;
}

.timeline-marker {
    position: absolute;
    left: 10px;
    top: 8px;
    width: 28px;
    height: 28px;
    background: linear-gradient(135deg, var(--primary), var(--secondary));
    border: 4px solid #ffffff;
    border-radius: 50%;
    z-index: 2;
    box-shadow: 0 4px 15px rgba(59, 130, 246, 0.35);
    transition: all 0.4s ease;
}

.timeline-item-aurora:hover .timeline-marker {
    transform: scale(1.3);
    box-shadow: 0 6px 25px rgba(59, 130, 246, 0.5);
}

.timeline-content-aurora {
    padding: 2rem;
    background: #ffffff;
    border-radius: 16px;
    transition: all 0.5s cubic-bezier(0.23, 1, 0.32, 1);
    border: 1px solid rgba(0, 0, 0, 0.05);
    box-shadow: 0 4px 20px -8px rgba(0, 0, 0, 0.1);
    position: relative;
    overflow: hidden;
}

.timeline-content-aurora::before {
    content: '';
    position: absolute;
    left: 0;
    top: 0;
    bottom: 0;
    width: 4px;
    background: var(--gradient-primary);
    opacity: 0;
    transition: opacity 0.4s ease;
}

.timeline-item-aurora:hover .timeline-content-aurora {
    transform: translateX(12px);
    background: #ffffff;
    box-shadow: 0 20px 50px -15px rgba(59, 130, 246, 0.2);
    border-color: rgba(59, 130, 246, 0.1);
}

.timeline-item-aurora:hover .timeline-content-aurora::before {
    opacity: 1;
}

.timeline-content-aurora .year {
    display: inline-block;
    font-weight: 800;
    font-size: 0.9rem;
    color: #ffffff;
    background: var(--gradient-primary);
    padding: 0.35rem 1rem;
    border-radius: var(--border-radius-full);
    margin-bottom: 0.75rem;
    letter-spacing: 0.5px;
}

.timeline-content-aurora h4 {
    font-size: 1.2rem;
    font-weight: 700;
    color: var(--text-primary);
    margin-bottom: 0.5rem;
}

.timeline-content-aurora p {
    font-size: 0.95rem;
    color: var(--text-secondary);
    margin-bottom: 0;
    line-height: 1.7;
}

/* Team Grid - Premium Design */
.team-grid-aurora {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(260px, 1fr));
    gap: 2.5rem;
}

.team-card-aurora {
    position: relative;
    background: #ffffff;
    border-radius: 24px;
    overflow: hidden;
    box-shadow: 0 10px 40px -15px rgba(0, 0, 0, 0.1);
    transition: all 0.5s cubic-bezier(0.23, 1, 0.32, 1);
    text-align: center;
    padding-bottom: 2rem;
    border: 1px solid rgba(0, 0, 0, 0.05);
}

.team-card-aurora::before {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    height: 120px;
    background: linear-gradient(135deg, rgba(59, 130, 246, 0.08) 0%, rgba(236, 72, 153, 0.08) 100%);
    z-index: 0;
}

.team-card-aurora:hover {
    transform: translateY(-15px);
    box-shadow: 0 30px 60px -20px rgba(59, 130, 246, 0.25);
}

.team-card-aurora .team-image {
    position: relative;
    z-index: 1;
    margin-top: 1.5rem;
    display: flex;
    justify-content: center;
}

.team-card-aurora .team-image img {
    width: 140px;
    height: 140px;
    border-radius: 50%;
    object-fit: cover;
    border: 5px solid #ffffff;
    box-shadow: 0 10px 30px -10px rgba(0, 0, 0, 0.2);
    transition: all 0.5s cubic-bezier(0.23, 1, 0.32, 1);
}

.team-card-aurora:hover .team-image img {
    transform: scale(1.08);
    border-color: rgba(59, 130, 246, 0.2);
    box-shadow: 0 15px 40px -10px rgba(59, 130, 246, 0.3);
}

.team-card-aurora h4 {
    font-size: 1.2rem;
    font-weight: 700;
    color: var(--text-primary);
    margin: 1.5rem 0 0.25rem;
    position: relative;
    z-index: 1;
}

.team-card-aurora>span {
    display: inline-block;
    font-size: 0.85rem;
    font-weight: 600;
    background: var(--gradient-primary);
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    background-clip: text;
    margin-bottom: 0.75rem;
    position: relative;
    z-index: 1;
}

.team-card-aurora>p {
    font-size: 0.9rem;
    color: var(--text-secondary);
    padding: 0 1.5rem;
    line-height: 1.65;
    margin-bottom: 1.25rem;
    position: relative;
    z-index: 1;
}

.team-card-aurora .team-social {
    display: flex;
    justify-content: center;
    gap: 0.75rem;
    position: relative;
    z-index: 1;
    transform: translateY(0);
    opacity: 1;
    background: none;
    /* Explicitly remove global dark gradient shadow */
}

.team-card-aurora .team-social a {
    width: 40px;
    height: 40px;
    display: flex;
    align-items: center;
    justify-content: center;
    background: linear-gradient(135deg, rgba(59, 130, 246, 0.1), rgba(236, 72, 153, 0.1));
    border-radius: 50%;
    color: var(--primary);
    font-size: 0.95rem;
    transition: all 0.4s cubic-bezier(0.23, 1, 0.32, 1);
}

.team-card-aurora .team-social a:hover {
    background: var(--gradient-primary);
    color: #ffffff;
    transform: translateY(-4px) scale(1.1);
    box-shadow: 0 10px 20px -8px rgba(59, 130, 246, 0.5);
}

/* CTA Section - Enhanced */
.cta-section {
    position: relative;
    padding: 6rem 0;
    background: linear-gradient(135deg, #3b82f6 0%, #8b5cf6 50%, #ec4899 100%);
    text-align: center;
    border-radius: 32px;
    margin: 4rem 1.5rem;
    overflow: hidden;
}

.cta-section::before {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    bottom: 0;
    background: url("data:image/svg+xml,%3Csvg width='60' height='60' viewBox='0 0 60 60' xmlns='http://www.w3.org/2000/svg'%3E%3Cg fill='none' fill-rule='evenodd'%3E%3Cg fill='%23ffffff' fill-opacity='0.03'%3E%3Cpath d='M36 34v-4h-2v4h-4v2h4v4h2v-4h4v-2h-4zm0-30V0h-2v4h-4v2h4v4h2V6h4V4h-4zM6 34v-4H4v4H0v2h4v4h2v-4h4v-2H6zM6 4V0H4v4H0v2h4v4h2V6h4V4H6z'/%3E%3C/g%3E%3C/g%3E%3C/svg%3E");
    opacity: 0.5;
}

.cta-section::after {
    content: '';
    position: absolute;
    top: -50%;
    right: -20%;
    width: 80%;
    height: 200%;
    background: radial-gradient(ellipse, rgba(255, 255, 255, 0.15) 0%, transparent 60%);
    pointer-events: none;
}

.cta-content {
    position: relative;
    z-index: 1;
}

.cta-content h2 {
    font-size: clamp(1.75rem, 4vw, 2.75rem);
    font-weight: 800;
    color: #ffffff;
    margin-bottom: 1rem;
    letter-spacing: -0.5px;
}

.cta-content h2 .gradient-text {
    background: linear-gradient(135deg, #ffffff 0%, rgba(255, 255, 255, 0.8) 100%);
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    background-clip: text;
}

.cta-content p {
    font-size: 1.15rem;
    color: rgba(255, 255, 255, 0.9);
    max-width: 500px;
    margin: 0 auto 2rem;
    line-height: 1.7;
}

.cta-buttons {
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 1.25rem;
    flex-wrap: wrap;
}

.cta-buttons .btn-main {
    background: #ffffff;
    color: var(--primary) !important;
    box-shadow: 0 10px 30px -10px rgba(0, 0, 0, 0.3);
    padding: 1rem 2rem;
    font-size: 0.95rem;
}

.cta-buttons .btn-main:hover {
    color: #ffffff !important;
    transform: translateY(-3px);
    box-shadow: 0 15px 40px -10px rgba(0, 0, 0, 0.4);
}

.cta-buttons .btn-secondary-main {
    background: rgba(255, 255, 255, 0.15);
    backdrop-filter: blur(10px);
    color: #ffffff !important;
    border: 1px solid rgba(255, 255, 255, 0.25);
    padding: 1rem 2rem;
    font-size: 0.95rem;
}

.cta-buttons .btn-secondary-main:hover {
    background: rgba(255, 255, 255, 0.25);
    border-color: rgba(255, 255, 255, 0.4);
}

/* Responsive Adjustments for About Page */
@media (max-width: 992px) {
    .page-header-aurora {
        padding: 140px 0 80px;
    }

    .values-grid-aurora {
        grid-template-columns: repeat(2, 1fr);
        gap: 1.5rem;
    }

    .team-grid-aurora {
        grid-template-columns: repeat(2, 1fr);
        gap: 2rem;
    }

    .cta-section {
        margin: 2rem 0;
        border-radius: 0;
    }
}

@media (max-width: 768px) {
    .page-header-aurora {
        padding: 120px 0 60px;
    }

    .page-header-aurora .lead {
        font-size: 1.1rem;
    }

    .values-grid-aurora {
        grid-template-columns: 1fr;
    }

    .value-card-aurora {
        padding: 2rem;
    }

    .timeline-vertical-aurora::before {
        left: 18px;
    }

    .timeline-marker {
        left: 7px;
        width: 24px;
        height: 24px;
    }

    .timeline-item-aurora {
        padding-left: 55px;
    }

    .team-grid-aurora {
        grid-template-columns: 1fr;
        max-width: 350px;
        margin: 0 auto;
    }
}

@media (max-width: 576px) {
    .timeline-content-aurora {
        padding: 1.5rem;
    }

    .cta-content h2 {
        font-size: 1.5rem;
    }

    .cta-buttons {
        flex-direction: column;
        width: 100%;
        padding: 0 1rem;
    }

    .cta-buttons .btn-main,
    .cta-buttons .btn-secondary-main {
        width: 100%;
    }
}

/* ─────────────────────────────────────────────────────────────────────────────
   NAVIGATION ICONS GROUP - AURORA DIGITAL
   ───────────────────────────────────────────────────────────────────────────── */
.nav-icons-group {
    display: flex;
    align-items: center;
    gap: 1.5rem;
    margin-left: 1rem;
}

.nav-icon-link {
    color: var(--text-secondary) !important;
    font-size: 1.1rem;
    transition: var(--transition-base);
    display: flex;
    align-items: center;
    position: relative;
}

.cart-badge {
    position: absolute;
    top: -5px;
    right: -8px;
    background: #007bff;
    /* Solid blue as requested */
    color: #fff !important;
    font-size: 10px;
    width: 16px;
    height: 16px;
    display: none;
    /* Controlled by JS */
    align-items: center;
    justify-content: center;
    border-radius: 50%;
    font-weight: 600;
    z-index: 10;
    line-height: 1;
}

.nav-icon-link:hover {
    color: var(--primary) !important;
}

/* Hide Dropdown Carets */
.nav-link.dropdown-toggle::after {
    display: none !important;
}

@media (max-width: 992px) {
    .nav-icons-group {
        margin-left: 0;
        margin-top: 1.5rem;
        margin-bottom: 1rem;
        width: 100%;
        justify-content: center;
        border-top: 1px solid var(--glass-border);
        padding-top: 1.5rem;
    }
}

/* ─────────────────────────────────────────────────────────────────────────────
   SCROLL REVEAL ANIMATIONS
   ───────────────────────────────────────────────────────────────────────────── */
.reveal {
    opacity: 0;
    transition: all 1.2s cubic-bezier(0.2, 0, 0.2, 1);
}

.reveal-up {
    transform: translateY(40px);
}

.reveal-down {
    transform: translateY(-40px);
}

.reveal-left {
    transform: translateX(-40px);
}

.reveal-right {
    transform: translateX(40px);
}

.reveal.active {
    opacity: 1;
    transform: translate(0, 0);
}

/* Delay Utilities - Smoother Staggering */
.delay-100 {
    transition-delay: 0.15s;
}

.delay-200 {
    transition-delay: 0.3s;
}

.delay-300 {
    transition-delay: 0.45s;
}

.delay-400 {
    transition-delay: 0.6s;
}

.delay-500 {
    transition-delay: 0.75s;
}

.delay-600 {
    transition-delay: 0.9s;
}

.delay-700 {
    transition-delay: 1.05s;
}

.delay-800 {
    transition-delay: 1.2s;
}

/* Newsletter Success Modal & Animations */
.success-icon-wrapper {
    display: flex;
    justify-content: center;
    align-items: center;
}

.success-icon-aurora {
    width: 80px;
    height: 80px;
    background: var(--gradient-primary);
    border-radius: 50%;
    display: flex;
    justify-content: center;
    align-items: center;
    color: white;
    font-size: 2.5rem;
    box-shadow: 0 10px 20px rgba(59, 130, 246, 0.3);
    animation: scaleIn 0.5s cubic-bezier(0.34, 1.56, 0.64, 1) forwards;
}

@keyframes scaleIn {
    0% {
        transform: scale(0);
        opacity: 0;
    }

    100% {
        transform: scale(1);
        opacity: 1;
    }
}

.success-icon-aurora i {
    animation: checkmark 0.3s ease-in-out 0.4s both;
}

@keyframes checkmark {
    0% {
        transform: scale(0);
        opacity: 0;
    }

    100% {
        transform: scale(1);
        opacity: 1;
    }
}

/* --- Aurora Custom Notifications --- */
.aurora-notif-container {
    position: fixed;
    top: 30px;
    left: 50%;
    transform: translateX(-50%);
    z-index: 9999;
    pointer-events: none;
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 15px;
}

.aurora-notif {
    background: #ffffff;
    color: var(--text-primary);
    padding: 16px 24px;
    border-radius: 16px;
    box-shadow: 0 15px 35px rgba(0, 0, 0, 0.1), 0 5px 15px rgba(0, 0, 0, 0.05);
    display: flex;
    align-items: center;
    gap: 12px;
    min-width: 320px;
    max-width: 90%;
    pointer-events: auto;
    border: 1px solid rgba(0, 0, 0, 0.05);
    transform: translateY(-20px);
    opacity: 0;
    transition: all 0.4s cubic-bezier(0.175, 0.885, 0.32, 1.275);
}

.aurora-notif.show {
    transform: translateY(0);
    opacity: 1;
}

.aurora-notif.hide {
    transform: translateY(-20px) scale(0.95);
    opacity: 0;
}

.aurora-notif i {
    font-size: 1.4rem;
    background: var(--gradient-primary);
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
}

.aurora-notif .notif-content {
    font-weight: 600;
    font-size: 0.95rem;
}

.aurora-notif .notif-close {
    margin-left: auto;
    cursor: pointer;
    opacity: 0.4;
    transition: opacity 0.2s;
}

.aurora-notif .notif-close:hover {
    opacity: 1;
}

/**
 * Aurora Digital - Shopping Cart Logic
 * Handles adding/removing items and persistence via localStorage
 */

const CART_STORAGE_KEY = 'aurora_cart_items';

// Get cart from localStorage or initialize empty
let cart = JSON.parse(localStorage.getItem(CART_STORAGE_KEY)) || [];

/**
 * Add a plan to the cart
 */
function addToCart(button) {
    const id = button.getAttribute('data-id');
    const name = button.getAttribute('data-name');
    const price = parseFloat(button.getAttribute('data-price'));
    const icon = button.getAttribute('data-icon') || 'fa-rocket';

    // Check if item already exists
    const existingItem = cart.find(item => item.id === id);

    if (existingItem) {
        showNotification(name + " is already in your cart.", "info");
        return;
    }

    const newItem = {
        id: id,
        name: name,
        price: price,
        icon: icon,
        type: 'Monthly Subscription'
    };

    cart.push(newItem);
    saveCart();
    updateCartUI();
    showNotification(name + " added to cart!", "success");

    // Optional: Visual feedback
    button.innerHTML = '<i class="fa-solid fa-check"></i> Added';
    button.classList.add('btn-success');
    button.classList.remove('btn-main', 'btn-secondary-main');

    setTimeout(() => {
        const originalText = id === 'professional' ? 'Add to Cart' : 'Add to Cart <i class="fa-solid fa-arrow-right"></i>';
        button.innerHTML = originalText;
        button.classList.remove('btn-success');
        button.classList.add(id === 'professional' ? 'btn-main' : 'btn-secondary-main');
    }, 2000);
}

/**
 * Custom Notification System (Branded Toast)
 */
function showNotification(message, type = 'info') {
    // Create container if it doesn't exist
    let container = document.querySelector('.aurora-notif-container');
    if (!container) {
        container = document.createElement('div');
        container.className = 'aurora-notif-container';
        document.body.appendChild(container);
    }

    // Create notification element
    const notif = document.createElement('div');
    notif.className = 'aurora-notif';

    const iconClass = type === 'success' ? 'fa-circle-check' : 'fa-circle-info';

    notif.innerHTML = `
        <i class="fa-solid ${iconClass}"></i>
        <div class="notif-content">${message}</div>
        <div class="notif-close" onclick="this.parentElement.remove()"><i class="fa-solid fa-xmark" style="-webkit-text-fill-color: initial; background: none;"></i></div>
    `;

    container.appendChild(notif);

    // Trigger animation with a slight delay
    setTimeout(() => notif.classList.add('show'), 50);

    // Auto-remove after 4 seconds
    setTimeout(() => {
        notif.classList.add('hide');
        setTimeout(() => notif.remove(), 400);
    }, 4000);
}

/**
 * Remove an item from the cart
 */
function removeFromCart(id) {
    cart = cart.filter(item => item.id !== id);
    saveCart();
    updateCartUI();
}

/**
 * Save cart to localStorage
 */
function saveCart() {
    localStorage.setItem(CART_STORAGE_KEY, JSON.stringify(cart));
}

/**
 * Update UI elements (badge, cart list)
 */
function updateCartUI() {
    // Update Badge Count (in header)
    const badges = document.querySelectorAll('.cart-badge');
    badges.forEach(badge => {
        badge.innerText = cart.length;
        badge.style.display = cart.length > 0 ? 'flex' : 'none';
    });

    // If on the cart page, render the list
    const cartContainer = document.getElementById('cart-items-container');
    if (cartContainer) {
        renderCartPage();
    }
}

/**
 * Render items on the dedicated Cart Page
 */
function renderCartPage() {
    const container = document.getElementById('cart-items-container');
    const subtotalEl = document.getElementById('cart-subtotal');
    const totalEl = document.getElementById('cart-total');

    if (!container) return;

    if (cart.length === 0) {
        container.innerHTML = `
            <div class="empty-cart-container py-5 text-center">
                <div class="glass-card mx-auto p-5" style="max-width: 550px; border-radius: 24px;">
                    <div class="mb-4 d-inline-flex align-items-center justify-content-center rounded-circle" 
                         style="width: 120px; height: 120px; background: linear-gradient(135deg, rgba(168, 85, 247, 0.1), rgba(59, 130, 246, 0.1)); border: 1px solid rgba(255, 255, 255, 0.1); box-shadow: 0 8px 32px rgba(168, 85, 247, 0.1);">
                        <i class="fa-solid fa-basket-shopping gradient-text" style="font-size: 3rem;"></i>
                    </div>
                    <h2 class="mb-3" style="font-family: 'Space Grotesk', sans-serif; font-weight: 700; letter-spacing: -1px;">Your <span class="gradient-text">Cart</span> is Empty</h2>
                    <p class="text-muted mb-4 px-4" style="font-size: 1.1rem; line-height: 1.6;">
                        It seems you haven't selected a plan yet. Our digital solutions are designed to scale with your ambition.
                    </p>
                    <div class="d-grid gap-3 d-sm-flex justify-content-sm-center">
                        <a href="pricing.html" class="btn-main py-3 px-5">
                            View Pricing Plans <i class="fa-solid fa-arrow-right ms-2 pulse"></i>
                        </a>
                    </div>
                </div>
            </div>
        `;
        subtotalEl.innerText = "$0.00";
        totalEl.innerText = "$0.00";
        return;
    }

    let html = '';
    let total = 0;

    cart.forEach(item => {
        total += item.price;
        html += `
            <div class="cart-item">
                <div class="d-flex align-items-center gap-3">
                    <div class="p-3 rounded-circle bg-dark border border-secondary" style="width: 60px; height: 60px; display: flex; align-items: center; justify-content: center;">
                        <i class="fa-solid ${item.icon} text-primary" style="font-size: 1.5rem;"></i>
                    </div>
                    <div class="item-info">
                        <h5>${item.name}</h5>
                        <span class="text-muted small">${item.type}</span>
                    </div>
                </div>
                <div class="d-flex align-items-center gap-4">
                    <span class="item-price" style="font-family: 'Space Mono', monospace; color: #a855f7; font-weight: bold; font-size: 1.3rem;">$${item.price.toFixed(2)}</span>
                    <button onclick="removeFromCart('${item.id}')" class="btn btn-sm btn-outline-danger border-0"><i class="fa-solid fa-trash"></i></button>
                </div>
            </div>
        `;
    });

    container.innerHTML = html;
    subtotalEl.innerText = `$${total.toFixed(2)}`;
    totalEl.innerText = `$${total.toFixed(2)}`;
}

// Initial UI update on page load
document.addEventListener('DOMContentLoaded', updateCartUI);

/**
* Template Name: Aurora Digital
* Description: Elegant IT Solutions & Healthcare Technology Template
* Version: 1.0.0
*/

(function () {
    "use strict";

    const select = (el, all = false) => {
        el = el.trim()
        if (all) {
            return [...document.querySelectorAll(el)]
        } else {
            return document.querySelector(el)
        }
    }

    const on = (type, el, listener, all = false) => {
        let selectEl = select(el, all)
        if (selectEl) {
            if (all) {
                selectEl.forEach(e => e.addEventListener(type, listener))
            } else {
                selectEl.addEventListener(type, listener)
            }
        }
    }

    // Sticky Header
    const mainNav = select('.main-nav');
    if (mainNav) {
        const navScrolled = () => {
            if (window.scrollY > 100) {
                mainNav.classList.add('scrolled')
            } else {
                mainNav.classList.remove('scrolled')
            }
        }
        window.addEventListener('load', navScrolled)
        document.addEventListener('scroll', navScrolled)
    }

    // Mobile nav toggle
    window.toggleMenu = function () {
        const navMenu = select('#navMenu');
        if (navMenu) {
            navMenu.classList.toggle('show');
        }
    }

    // Back to top
    const backToTop = select('#backToTop');
    if (backToTop) {
        const toggleBackToTop = () => {
            if (window.scrollY > 300) {
                backToTop.classList.add('show')
            } else {
                backToTop.classList.remove('show')
            }
        }
        window.addEventListener('load', toggleBackToTop)
        document.addEventListener('scroll', toggleBackToTop)

        backToTop.addEventListener('click', () => {
            window.scrollTo({ top: 0, behavior: 'smooth' });
        });
    }

    // Counter Animation
    const counters = document.querySelectorAll('.counter-number');

    if (counters.length > 0) {
        const animateCounter = (counter) => {
            const target = +counter.getAttribute('data-target');
            const duration = 2000; // 2 seconds
            const increment = target / (duration / 16); // 60fps approx

            let current = 0;
            const updateCount = () => {
                current += increment;
                if (current < target) {
                    counter.innerText = Math.ceil(current);
                    requestAnimationFrame(updateCount);
                } else {
                    counter.innerText = target;
                }
            };
            updateCount();
        };

        const counterObserver = new IntersectionObserver((entries, observer) => {
            entries.forEach(entry => {
                if (entry.isIntersecting) {
                    const counter = entry.target.querySelector('.counter-number');
                    if (counter && counter.innerText === '0') {
                        animateCounter(counter);
                    }
                    observer.unobserve(entry.target);
                }
            });
        }, { threshold: 0.1 });

        const counterItems = document.querySelectorAll('.counter-item');
        counterItems.forEach(item => {
            counterObserver.observe(item);
        });
    }

    // FAQ Accordion
    const faqItems = document.querySelectorAll('.faq-item');
    faqItems.forEach(item => {
        const question = item.querySelector('.faq-question');
        if (question) {
            question.addEventListener('click', () => {
                const isActive = item.classList.contains('active');
                faqItems.forEach(i => i.classList.remove('active'));
                if (!isActive) {
                    item.classList.add('active');
                }
            });
        }
    });

    // Tooltips
    if (typeof bootstrap !== 'undefined') {
        var tooltipTriggerList = [].slice.call(document.querySelectorAll('[data-bs-toggle="tooltip"]'))
        var tooltipList = tooltipTriggerList.map(function (tooltipTriggerEl) {
            return new bootstrap.Tooltip(tooltipTriggerEl)
        })
    }

    // Scroll Reveal Animation
    const revealElements = document.querySelectorAll('.reveal');
    if (revealElements.length > 0) {
        const revealObserver = new IntersectionObserver((entries) => {
            entries.forEach(entry => {
                if (entry.isIntersecting) {
                    entry.target.classList.add('active');
                    // Optional: unobserve if you only want it once
                    // revealObserver.unobserve(entry.target);
                }
            });
        }, {
            threshold: 0.15,
            rootMargin: '0px 0px -50px 0px'
        });

        revealElements.forEach(el => revealObserver.observe(el));
    }

    // Blog State & Pagination Logic
    let currentBlogFilter = 'all';
    let currentBlogSearch = '';
    let currentBlogPage = 1;
    const cardsPerPage = 4;

    const filterLinks = document.querySelectorAll('.category-list-aurora a');
    const blogCards = document.querySelectorAll('.blog-card-aurora');
    const pagination = document.querySelector('.pagination-aurora');
    const paginationUl = pagination ? pagination.querySelector('.pagination') : null;

    function updateBlogDisplay() {
        if (!blogCards.length) return;

        let filteredCards = Array.from(blogCards).filter(card => {
            const cardCategory = card.getAttribute('data-category');
            const title = card.querySelector('h3, h2').innerText.toLowerCase().replace(/\s+/g, ' ').trim();
            const content = card.querySelector('p').innerText.toLowerCase().replace(/\s+/g, ' ').trim();
            const searchNormalized = currentBlogSearch.toLowerCase().replace(/\s+/g, ' ').trim();

            const searchMatch = searchNormalized === "" ||
                title.includes(searchNormalized) ||
                content.includes(searchNormalized) ||
                cardCategory.toLowerCase().includes(searchNormalized);
            const categoryMatch = currentBlogFilter === 'all' || currentBlogFilter === cardCategory;

            return searchMatch && categoryMatch;
        });

        const totalPages = Math.ceil(filteredCards.length / cardsPerPage);
        if (currentBlogPage > totalPages) currentBlogPage = totalPages || 1;

        blogCards.forEach(card => card.style.display = 'none');

        const start = (currentBlogPage - 1) * cardsPerPage;
        const end = start + cardsPerPage;
        const pageCards = filteredCards.slice(start, end);

        pageCards.forEach((card, index) => {
            card.style.display = 'block';
            setTimeout(() => {
                card.classList.add('active');
            }, 50 * index);
        });

        if (paginationUl) {
            if (filteredCards.length <= cardsPerPage) {
                pagination.style.display = 'none';
            } else {
                pagination.style.display = 'block';
                renderPagination(totalPages);
            }
        }

        const noResults = document.getElementById('no-results-message');
        if (noResults) {
            noResults.style.display = filteredCards.length === 0 ? 'block' : 'none';
            if (filteredCards.length === 0) noResults.classList.add('active');
        }
    }

    function renderPagination(totalPages) {
        if (!paginationUl) return;
        paginationUl.innerHTML = '';

        const prevLi = document.createElement('li');
        prevLi.className = `page-item ${currentBlogPage === 1 ? 'disabled' : ''}`;
        prevLi.innerHTML = `<a class="page-link" href="#"><i class="fa-solid fa-chevron-left"></i></a>`;
        prevLi.addEventListener('click', (e) => {
            e.preventDefault();
            if (currentBlogPage > 1) {
                currentBlogPage--;
                updateBlogDisplay();
                const blogSection = document.querySelector('.blog-grid-aurora') || blogCards[0];
                if (blogSection) window.scrollTo({ top: blogSection.offsetTop - 100, behavior: 'smooth' });
            }
        });
        paginationUl.appendChild(prevLi);

        for (let i = 1; i <= totalPages; i++) {
            const li = document.createElement('li');
            li.className = `page-item ${currentBlogPage === i ? 'active' : ''}`;
            li.innerHTML = `<a class="page-link" href="#">${i}</a>`;
            li.addEventListener('click', (e) => {
                e.preventDefault();
                currentBlogPage = i;
                updateBlogDisplay();
                const blogSection = document.querySelector('.blog-grid-aurora') || blogCards[0];
                if (blogSection) window.scrollTo({ top: blogSection.offsetTop - 100, behavior: 'smooth' });
            });
            paginationUl.appendChild(li);
        }

        const nextLi = document.createElement('li');
        nextLi.className = `page-item ${currentBlogPage === totalPages ? 'disabled' : ''}`;
        nextLi.innerHTML = `<a class="page-link" href="#"><i class="fa-solid fa-chevron-right"></i></a>`;
        nextLi.addEventListener('click', (e) => {
            e.preventDefault();
            if (currentBlogPage < totalPages) {
                currentBlogPage++;
                updateBlogDisplay();
                const blogSection = document.querySelector('.blog-grid-aurora') || blogCards[0];
                if (blogSection) window.scrollTo({ top: blogSection.offsetTop - 100, behavior: 'smooth' });
            }
        });
        paginationUl.appendChild(nextLi);
    }

    if (filterLinks.length > 0) {
        filterLinks.forEach(link => {
            link.addEventListener('click', (e) => {
                e.preventDefault();
                const sInput = document.getElementById('blog-search-input');
                if (sInput) sInput.value = "";
                currentBlogSearch = "";
                currentBlogFilter = link.getAttribute('data-filter');
                currentBlogPage = 1;
                filterLinks.forEach(l => l.parentElement.classList.remove('active'));
                link.parentElement.classList.add('active');
                updateBlogDisplay();
            });
        });
    }

    const searchInput = document.getElementById('blog-search-input');
    const searchBtn = document.getElementById('blog-search-btn');
    const suggestionsDropdown = document.getElementById('suggestions-dropdown');

    if (searchInput && searchBtn) {
        const performSearch = (specificQuery = null) => {
            const query = specificQuery !== null ? specificQuery.trim() : searchInput.value.trim();
            if (specificQuery !== null) searchInput.value = specificQuery;
            if (suggestionsDropdown) suggestionsDropdown.style.display = 'none';

            currentBlogSearch = query;
            currentBlogPage = 1;

            // Reset category filters when searching
            if (query !== "") {
                currentBlogFilter = 'all';
                if (filterLinks) {
                    filterLinks.forEach(l => l.parentElement.classList.remove('active'));
                    const allBtn = Array.from(filterLinks).find(l => l.getAttribute('data-filter') === 'all');
                    if (allBtn) allBtn.parentElement.classList.add('active');
                }
            }
            updateBlogDisplay();
        };

        if (suggestionsDropdown) {
            searchInput.addEventListener('input', () => {
                const query = searchInput.value.toLowerCase().trim();
                if (query.length < 1) {
                    suggestionsDropdown.style.display = 'none';
                    return;
                }
                const matches = Array.from(blogCards).filter(card => {
                    const title = card.querySelector('h3, h2').innerText.toLowerCase();
                    const category = card.getAttribute('data-category').toLowerCase();
                    return title.includes(query) || category.includes(query);
                }).slice(0, 5);
                if (matches.length > 0) {
                    suggestionsDropdown.innerHTML = matches.map(card => {
                        const title = card.querySelector('h3, h2').innerText.replace(/\s+/g, ' ').trim();
                        const category = card.getAttribute('data-category');
                        const img = card.querySelector('img').src;
                        return `
                        <div class="suggestion-item" onclick="performBlogSearch('${title.replace(/'/g, "\\'")}')">
                            <img src="${img}" class="suggestion-thumb" alt="${title}">
                            <div class="suggestion-info">
                                <span class="suggestion-title">${title}</span>
                                <span class="suggestion-category">${category.charAt(0).toUpperCase() + category.slice(1)}</span>
                            </div>
                        </div>`;
                    }).join('');
                    suggestionsDropdown.style.display = 'block';
                } else {
                    suggestionsDropdown.style.display = 'none';
                }
            });
            window.performBlogSearch = (title) => performSearch(title);
            document.addEventListener('click', (e) => {
                if (!searchInput.contains(e.target) && !suggestionsDropdown.contains(e.target)) {
                    suggestionsDropdown.style.display = 'none';
                }
            });
        }

        searchBtn.addEventListener('click', () => performSearch());
        searchInput.addEventListener('keyup', (e) => {
            if (e.key === 'Enter') performSearch();
        });
    }


    // Newsletter Form Submission
    const newsletterForm = document.getElementById('newsletterForm');
    if (newsletterForm) {
        newsletterForm.addEventListener('submit', function (e) {
            e.preventDefault();
            const emailInput = this.querySelector('input[type="email"]');

            // Here you would typically send the data to a server
            console.log('Newsletter subscription for:', emailInput.value);

            // Show Success Modal
            if (typeof bootstrap !== 'undefined') {
                const newsletterModal = new bootstrap.Modal(document.getElementById('newsletterModal'));
                newsletterModal.show();

                // Clear the form
                this.reset();
            }
        });
    }

    updateBlogDisplay();
})();

#!/usr/bin/perl

use strict;
use warnings;
use IPC::Open2;

# An example hook script to integrate Watchman
# (https://facebook.github.io/watchman/) with git to speed up detecting
# new and modified files.
#
# The hook is passed a version (currently 2) and last update token
# formatted as a string and outputs to stdout a new update token and
# all files that have been modified since the update token. Paths must
# be relative to the root of the working tree and separated by a single NUL.
#
# To enable this hook, rename this file to "query-watchman" and set
# 'git config core.fsmonitor .git/hooks/query-watchman'
#
my ($version, $last_update_token) = @ARGV;

# Uncomment for debugging
# print STDERR "$0 $version $last_update_token\n";

# Check the hook interface version
if ($version ne 2) {
	die "Unsupported query-fsmonitor hook version '$version'.\n" .
	    "Falling back to scanning...\n";
}

my $git_work_tree = get_working_dir();

my $retry = 1;

my $json_pkg;
eval {
	require JSON::XS;
	$json_pkg = "JSON::XS";
	1;
} or do {
	require JSON::PP;
	$json_pkg = "JSON::PP";
};

launch_watchman();

sub launch_watchman {
	my $o = watchman_query();
	if (is_work_tree_watched($o)) {
		output_result($o->{clock}, @{$o->{files}});
	}
}

sub output_result {
	my ($clockid, @files) = @_;

	# Uncomment for debugging watchman output
	# open (my $fh, ">", ".git/watchman-output.out");
	# binmode $fh, ":utf8";
	# print $fh "$clockid\n@files\n";
	# close $fh;

	binmode STDOUT, ":utf8";
	print $clockid;
	print "\0";
	local $, = "\0";
	print @files;
}

sub watchman_clock {
	my $response = qx/watchman clock "$git_work_tree"/;
	die "Failed to get clock id on '$git_work_tree'.\n" .
		"Falling back to scanning...\n" if $? != 0;

	return $json_pkg->new->utf8->decode($response);
}

sub watchman_query {
	my $pid = open2(\*CHLD_OUT, \*CHLD_IN, 'watchman -j --no-pretty')
	or die "open2() failed: $!\n" .
	"Falling back to scanning...\n";

	# In the query expression below we're asking for names of files that
	# changed since $last_update_token but not from the .git folder.
	#
	# To accomplish this, we're using the "since" generator to use the
	# recency index to select candidate nodes and "fields" to limit the
	# output to file names only. Then we're using the "expression" term to
	# further constrain the results.
	my $last_update_line = "";
	if (substr($last_update_token, 0, 1) eq "c") {
		$last_update_token = "\"$last_update_token\"";
		$last_update_line = qq[\n"since": $last_update_token,];
	}
	my $query = <<"	END";
		["query", "$git_work_tree", {$last_update_line
			"fields": ["name"],
			"expression": ["not", ["dirname", ".git"]]
		}]
	END

	# Uncomment for debugging the watchman query
	# open (my $fh, ">", ".git/watchman-query.json");
	# print $fh $query;
	# close $fh;

	print CHLD_IN $query;
	close CHLD_IN;
	my $response = do {local $/; <CHLD_OUT>};

	# Uncomment for debugging the watch response
	# open ($fh, ">", ".git/watchman-response.json");
	# print $fh $response;
	# close $fh;

	die "Watchman: command returned no output.\n" .
	"Falling back to scanning...\n" if $response eq "";
	die "Watchman: command returned invalid output: $response\n" .
	"Falling back to scanning...\n" unless $response =~ /^\{/;

	return $json_pkg->new->utf8->decode($response);
}

sub is_work_tree_watched {
	my ($output) = @_;
	my $error = $output->{error};
	if ($retry > 0 and $error and $error =~ m/unable to resolve root .* directory (.*) is not watched/) {
		$retry--;
		my $response = qx/watchman watch "$git_work_tree"/;
		die "Failed to make watchman watch '$git_work_tree'.\n" .
		    "Falling back to scanning...\n" if $? != 0;
		$output = $json_pkg->new->utf8->decode($response);
		$error = $output->{error};
		die "Watchman: $error.\n" .
		"Falling back to scanning...\n" if $error;

		# Uncomment for debugging watchman output
		# open (my $fh, ">", ".git/watchman-output.out");
		# close $fh;

		# Watchman will always return all files on the first query so
		# return the fast "everything is dirty" flag to git and do the
		# Watchman query just to get it over with now so we won't pay
		# the cost in git to look up each individual file.
		my $o = watchman_clock();
		$error = $output->{error};

		die "Watchman: $error.\n" .
		"Falling back to scanning...\n" if $error;

		output_result($o->{clock}, ("/"));
		$last_update_token = $o->{clock};

		eval { launch_watchman() };
		return 0;
	}

	die "Watchman: $error.\n" .
	"Falling back to scanning...\n" if $error;

	return 1;
}

sub get_working_dir {
	my $working_dir;
	if ($^O =~ 'msys' || $^O =~ 'cygwin') {
		$working_dir = Win32::GetCwd();
		$working_dir =~ tr/\\/\//;
	} else {
		require Cwd;
		$working_dir = Cwd::cwd();
	}

	return $working_dir;
}
